window.AGILE_QUESTIONS = [
// ==== Chapter 1: Agile Software Development (IDs 1001-1150) ====
{id:1001,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"easy",question:"Which of the following is a value stated in the Agile Manifesto?",options:["A. Comprehensive documentation over working software","B. Individuals and interactions over processes and tools","C. Contract negotiation over customer collaboration","D. Following a plan over responding to change"],answer:1,explanation:"The Agile Manifesto values individuals and interactions over processes and tools."},
{id:1002,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"easy",question:"How many core values does the Agile Manifesto define?",options:["A. Two","B. Four","C. Six","D. Twelve"],answer:1,explanation:"The Agile Manifesto defines four core values."},
{id:1003,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"easy",question:"Which of the following is one of the twelve Agile principles?",options:["A. Our highest priority is to satisfy the customer through early and continuous delivery of valuable software","B. Deliver software at the end of the project","C. Maximize work in progress to increase throughput","D. Avoid changes to requirements once development has started"],answer:0,explanation:"Satisfying the customer through early and continuous delivery is the first Agile principle."},
{id:1004,chapter:"Agile Software Development",topic:"Agile vs Traditional",difficulty:"medium",question:"Which statement BEST describes the difference between Agile and traditional software development?",options:["A. Agile has no testing phase; traditional has dedicated testing phases","B. Agile embraces change; traditional tries to minimize change after planning","C. Agile requires no documentation; traditional requires comprehensive documentation","D. Agile has no roles; traditional has defined roles"],answer:1,explanation:"Agile embraces change and adapts to it, whereas traditional models try to minimize change after initial planning."},
{id:1005,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"easy",question:"In Scrum, what is a Sprint?",options:["A. A time-boxed iteration typically lasting 1-4 weeks","B. A daily meeting","C. The product backlog","D. A type of user story"],answer:0,explanation:"A Sprint is a time-boxed iteration, typically 1-4 weeks, where a usable product increment is created."},
{id:1006,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"Who is responsible for maximizing the value of the product in Scrum?",options:["A. Scrum Master","B. Product Owner","C. Development Team","D. Stakeholders"],answer:1,explanation:"The Product Owner is responsible for maximizing the value of the product and managing the product backlog."},
{id:1007,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"What is the purpose of the Daily Scrum?",options:["A. To report status to management","B. To synchronize activities and plan work for the next 24 hours","C. To discuss technical architecture","D. To review the sprint backlog with stakeholders"],answer:1,explanation:"The Daily Scrum synchronizes team activities and allows the team to plan work for the next 24 hours."},
{id:1008,chapter:"Agile Software Development",topic:"Kanban",difficulty:"easy",question:"What is the primary focus of Kanban?",options:["A. Time-boxed iterations","B. Visualizing work and limiting work in progress","C. Comprehensive documentation","D. Detailed upfront planning"],answer:1,explanation:"Kanban focuses on visualizing work and limiting work in progress to optimize flow."},
{id:1009,chapter:"Agile Software Development",topic:"Kanban",difficulty:"medium",question:"In Kanban, what does limiting WIP help achieve?",options:["A. Increases multitasking efficiency","B. Prevents bottlenecks and improves flow","C. Eliminates the need for testing","D. Increases work capacity infinitely"],answer:1,explanation:"Limiting WIP prevents bottlenecks and helps maintain a steady flow of work through the system."},
{id:1010,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"easy",question:"Which of the following is an Extreme Programming practice?",options:["A. Pair programming","B. Annual planning","C. Individual code ownership","D. Minimal customer involvement"],answer:0,explanation:"Pair programming is a core XP practice where two developers work together at one workstation."},
{id:1011,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"medium",question:"What does Test-Driven Development require a developer to do first?",options:["A. Write tests after implementation is complete","B. Write a failing test before writing production code","C. Write tests only for critical functions","D. Automate all tests before starting the project"],answer:1,explanation:"TDD requires writing a failing test first, then writing the minimum code to pass it, then refactoring."},
{id:1012,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"medium",question:"The Agile principle about welcoming changing requirements is primarily intended to:",options:["A. Allow scope creep","B. Provide competitive advantage to the customer","C. Eliminate the need for planning","D. Reduce testing effort"],answer:1,explanation:"Welcoming changing requirements allows the team to adapt and give customers a competitive advantage."},
{id:1013,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"medium",question:"The Agile Manifesto values working software over comprehensive documentation. This means:",options:["A. No documentation is needed in Agile projects","B. Working software is more important but documentation still has value","C. Documentation should be eliminated entirely","D. Code is the only form of communication"],answer:1,explanation:"The manifesto says working software is MORE valued, but documentation still has value."},
{id:1014,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"What is the Sprint Retrospective used for?",options:["A. Demonstrating the sprint increment to stakeholders","B. Planning the next sprint backlog","C. Inspecting how the team worked and identifying improvements","D. Reviewing the product backlog with the Product Owner"],answer:2,explanation:"The Sprint Retrospective is where the team inspects itself and creates a plan for improvements."},
{id:1015,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"hard",question:"A Development Team consistently fails to complete all Sprint Backlog items. The MOST appropriate action for the Scrum Master is to:",options:["A. Extend the sprint duration","B. Reduce the sprint velocity target","C. Help the team understand why and improve sprint planning","D. Report the team to management"],answer:2,explanation:"The Scrum Master helps the team improve its planning and estimation, not punish or extend sprints."},
{id:1016,chapter:"Agile Software Development",topic:"Agile vs Traditional",difficulty:"hard",question:"In which scenario would a traditional waterfall approach be MORE appropriate than Agile?",options:["A. A startup building a new web application","B. A project with fixed well-understood requirements and strict regulatory compliance","C. A mobile app with evolving user requirements","D. A DevOps team doing continuous delivery"],answer:1,explanation:"Waterfall suits fixed, well-understood requirements and regulatory compliance requiring documented phases."},
{id:1017,chapter:"Agile Software Development",topic:"Lean",difficulty:"medium",question:"Which Lean principle is focused on eliminating waste?",options:["A. Amplify learning","B. Eliminate waste","C. Deliver as fast as possible","D. Build integrity in"],answer:1,explanation:"Eliminate waste is a core Lean principle â€” anything that does not add value to the customer is waste."},
{id:1018,chapter:"Agile Software Development",topic:"Lean",difficulty:"medium",question:"In Lean software development, partially done work is considered:",options:["A. An asset","B. A type of waste","C. A necessary buffer","D. Progress toward completion"],answer:1,explanation:"Partially done work is waste in Lean â€” it consumes resources without delivering value."},
{id:1019,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"easy",question:"Which of the following BEST describes the Agile approach to customer collaboration?",options:["A. Customers define requirements at the start and are not involved after that","B. Customers collaborate throughout the project providing feedback and direction","C. Customers only review the final product before release","D. Customers sign off requirements before development begins"],answer:1,explanation:"Agile promotes continuous customer collaboration throughout the development lifecycle."},
{id:1020,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"hard",question:"At regular intervals the team reflects on how to become more effective. This refers to which ceremony?",options:["A. Sprint Review","B. Daily Scrum","C. Sprint Retrospective","D. Sprint Planning"],answer:2,explanation:"The Sprint Retrospective is the ceremony where the team reflects and adapts its working process."},
{id:1021,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"hard",question:"What is the Definition of Ready in Agile?",options:["A. Criteria that must be met before a user story is considered done","B. Criteria that must be met before a user story can be taken into a sprint","C. The list of tests that must pass before release","D. The Product Owner approval of completed work"],answer:1,explanation:"The Definition of Ready defines criteria a user story must meet before the team takes it into sprint planning."},
{id:1022,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"hard",question:"In XP, what is the concept of collective code ownership?",options:["A. Only senior developers can modify code","B. Any developer can change any part of the code at any time","C. The lead developer owns all code","D. Code ownership is assigned by management"],answer:1,explanation:"Collective code ownership means any team member can modify any part of the codebase."},
{id:1023,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"hard",question:"Which Agile Manifesto statement BEST supports responding to change?",options:["A. Working software over comprehensive documentation","B. Individuals and interactions over processes and tools","C. Customer collaboration over contract negotiation","D. Responding to change over following a plan"],answer:3,explanation:"Responding to change over following a plan directly supports adapting to new information and requirements."},
{id:1024,chapter:"Agile Software Development",topic:"Kanban",difficulty:"hard",question:"A Kanban team notices a column consistently has items stuck. This is BEST described as:",options:["A. A WIP limit violation","B. A bottleneck in the flow","C. A sprint failure","D. A backlog refinement issue"],answer:1,explanation:"Items consistently stuck in one column indicate a bottleneck limiting overall flow."},
{id:1025,chapter:"Agile Software Development",topic:"Lean",difficulty:"hard",question:"Which of the following is NOT a type of waste in Lean software development?",options:["A. Partially done work","B. Extra features","C. Continuous integration","D. Task switching"],answer:2,explanation:"Continuous integration is a best practice. Partially done work, extra features, and task switching are all waste."},
{id:1026,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"extreme",question:"A team delivers working software every two weeks but code quality is deteriorating. Which Agile principle is MOST violated?",options:["A. Deliver working software frequently","B. Continuous attention to technical excellence and good design","C. Welcome changing requirements","D. Business people and developers must work together daily"],answer:1,explanation:"Continuous attention to technical excellence is a core Agile principle that prevents technical debt accumulation."},
{id:1027,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"extreme",question:"The Product Owner keeps adding items mid-sprint causing the team to miss sprint goals. The Scrum Master should:",options:["A. Approve additions since the PO has authority","B. Protect the team from scope changes during the sprint","C. Extend the sprint to accommodate extra work","D. Ask the team to work overtime"],answer:1,explanation:"The Scrum Master protects the team from scope changes during a sprint, ensuring sprint goals can be met."},
{id:1028,chapter:"Agile Software Development",topic:"Agile vs Traditional",difficulty:"extreme",question:"Why might Agile teams still produce documentation?",options:["A. Because the Agile Manifesto requires documentation","B. Because some documentation provides genuine value to the team or stakeholders","C. Because traditional managers require it","D. Because documentation compensates for poor code quality"],answer:1,explanation:"Agile produces documentation when it provides genuine value â€” just enough and just in time."},
{id:1029,chapter:"Agile Software Development",topic:"Kanban",difficulty:"extreme",question:"In Kanban, cycle time represents:",options:["A. The time from sprint start to sprint end","B. The time from when work begins to when it is delivered","C. The number of items completed per sprint","D. The time spent in daily standups"],answer:1,explanation:"Cycle time measures how long from when work starts on an item to when it is delivered."},
{id:1030,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"extreme",question:"In XP, continuous integration means:",options:["A. Integrating code once per sprint","B. Developers integrate their work into a shared repository several times per day","C. Running all tests at the end of the sprint","D. Merging all feature branches before release"],answer:1,explanation:"Continuous integration in XP means developers integrate their changes into the shared codebase several times a day."},
{id:1031,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"medium",question:"Which Agile value emphasizes human collaboration over contractual commitments?",options:["A. Working software over comprehensive documentation","B. Responding to change over following a plan","C. Customer collaboration over contract negotiation","D. Individuals and interactions over processes and tools"],answer:2,explanation:"Customer collaboration over contract negotiation emphasizes partnership over rigid contractual obligations."},
{id:1032,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"easy",question:"What happens at the Sprint Review?",options:["A. The team discusses what went wrong in the sprint","B. The increment is demonstrated to stakeholders for feedback","C. The product backlog is created from scratch","D. Velocity is calculated and reported"],answer:1,explanation:"The Sprint Review demonstrates the sprint increment to stakeholders to get feedback."},
{id:1033,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"What is the role of the Scrum Master?",options:["A. Managing the team and assigning tasks","B. Serving the team by removing impediments and coaching on Scrum practices","C. Making technical architecture decisions","D. Writing user stories and managing the backlog"],answer:1,explanation:"The Scrum Master removes obstacles, facilitates events, and coaches on Scrum practices."},
{id:1034,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"medium",question:"According to Agile principles, the preferred measure of progress is:",options:["A. Number of documents produced","B. Working software","C. Lines of code written","D. Tests written"],answer:1,explanation:"Working software is the primary measure of progress in Agile development."},
{id:1035,chapter:"Agile Software Development",topic:"Lean",difficulty:"easy",question:"Which Lean concept focuses on visualizing the entire value stream?",options:["A. Value stream mapping","B. Sprint planning","C. Pair programming","D. Test automation"],answer:0,explanation:"Value stream mapping visualizes the entire flow of value from concept to delivery."},
{id:1036,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"medium",question:"An Agile team is collocated. What advantage does this MOST directly provide?",options:["A. Reduces the need for automated testing","B. Enables face-to-face communication and faster decision-making","C. Eliminates the need for retrospectives","D. Allows the team to skip sprint planning"],answer:1,explanation:"Collocated teams benefit from face-to-face communication, the richest and fastest communication form."},
{id:1037,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"hard",question:"In Scrum, what is the product backlog?",options:["A. A list of bugs to fix in the next sprint","B. An ordered list of everything that might be needed in the product","C. The set of tasks assigned to developers for the current sprint","D. A document describing the system architecture"],answer:1,explanation:"The product backlog is an ordered list of all desired work for the product, managed by the Product Owner."},
{id:1038,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"medium",question:"What is the purpose of refactoring in XP?",options:["A. Adding new features","B. Improving internal code structure without changing behavior","C. Rewriting the entire codebase","D. Removing all automated tests"],answer:1,explanation:"Refactoring improves code structure without changing external behavior, reducing technical debt."},
{id:1039,chapter:"Agile Software Development",topic:"Agile vs Traditional",difficulty:"medium",question:"In Agile, requirements are typically expressed as:",options:["A. Detailed functional specifications","B. User stories","C. UML diagrams","D. Use case documents"],answer:1,explanation:"User stories are the typical format for expressing requirements in Agile, focusing on value to the user."},
{id:1040,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"easy",question:"What does the Agile principle about sustainable development mean?",options:["A. Projects should use green energy","B. The team should maintain a constant pace indefinitely","C. Only senior developers should write code","D. Sprints should never be longer than one week"],answer:1,explanation:"Sustainable development means maintaining a constant pace â€” avoiding burnout and unsustainable crunch."},
{id:1041,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"What is the maximum recommended size of a Scrum Development Team?",options:["A. 3","B. 9","C. 15","D. 20"],answer:1,explanation:"Scrum recommends 3-9 people for the Development Team to maintain effective communication."},
{id:1042,chapter:"Agile Software Development",topic:"Kanban",difficulty:"medium",question:"What is a Cumulative Flow Diagram used for in Kanban?",options:["A. Tracking sprint velocity","B. Visualizing the amount of work in each stage over time","C. Planning iteration capacity","D. Recording defect counts"],answer:1,explanation:"A CFD shows how much work is in each state over time, helping identify bottlenecks and measure flow."},
{id:1043,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"hard",question:"In XP, a Spike is:",options:["A. A critical bug to be fixed immediately","B. A time-boxed research or investigation activity to reduce uncertainty","C. A type of user story","D. A performance test"],answer:1,explanation:"A spike is a time-boxed investigation to gain knowledge needed to reduce risk or uncertainty."},
{id:1044,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"hard",question:"According to the Agile Manifesto, the most efficient method of conveying information is:",options:["A. Written documentation","B. Email communication","C. Face-to-face conversation","D. Video conferencing"],answer:2,explanation:"The Agile Manifesto states face-to-face conversation is the most efficient and effective method."},
{id:1045,chapter:"Agile Software Development",topic:"Lean",difficulty:"hard",question:"In Lean, pull systems are preferred over push systems because:",options:["A. They are easier to implement","B. They reduce overproduction by only producing what is needed when needed","C. They allow faster delivery","D. They eliminate the need for testing"],answer:1,explanation:"Pull systems reduce waste by only producing items when there is actual demand."},
{id:1046,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"hard",question:"An Agile team is distributed across different time zones. Which practice MOST helps maintain cohesion?",options:["A. Eliminate daily standups","B. Use asynchronous tools and overlap hours for key meetings","C. Have all team members work night shifts","D. Hire a project manager to coordinate"],answer:1,explanation:"Distributed teams benefit from asynchronous tools plus defined overlap windows for critical synchronous communication."},
{id:1047,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"extreme",question:"A company has 60 developers working on one product. They decide to use Scrum. Which approach is MOST appropriate?",options:["A. Create one large Scrum team of 60","B. Use a scaling framework like SAFe or LeSS with multiple Scrum teams","C. Use traditional waterfall instead","D. Have all 60 developers attend every Daily Scrum"],answer:1,explanation:"Scaled Agile frameworks like SAFe or LeSS are designed to apply Scrum at scale across multiple teams."},
{id:1048,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"extreme",question:"The Agile principle of building projects around motivated individuals implies that management should:",options:["A. Micromanage team members to ensure delivery","B. Trust the team, provide support, and get out of their way","C. Define detailed processes for all work","D. Measure individual performance through metrics"],answer:1,explanation:"Building around motivated individuals means trusting them, supporting their needs, and empowering them to deliver."},
{id:1049,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"extreme",question:"In XP, small releases means:",options:["A. Releasing only bug fixes","B. Deploying small functional slices of software frequently","C. Limiting releases to minor features only","D. Reducing the size of the development team"],answer:1,explanation:"Small releases in XP means delivering small, working increments frequently to get early feedback."},
{id:1050,chapter:"Agile Software Development",topic:"Kanban",difficulty:"extreme",question:"A Kanban team's lead time is increasing while WIP limits are being respected. The MOST likely cause is:",options:["A. Too many developers on the team","B. Increased complexity or blocking issues in the work itself","C. The WIP limits are too low","D. The team is not using story points"],answer:1,explanation:"If WIP limits are respected but lead time grows, the work itself has become more complex or blocked."},
{id:1051,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"Which of the following is NOT a Scrum event?",options:["A. Sprint Planning","B. Sprint Review","C. Backlog Grooming","D. Sprint Retrospective"],answer:2,explanation:"Backlog Refinement is a common practice but not one of the five formal Scrum events."},
{id:1052,chapter:"Agile Software Development",topic:"Agile vs Traditional",difficulty:"easy",question:"In Agile, the scope of work is considered:",options:["A. Fixed at the start of the project","B. Flexible and can evolve based on feedback","C. Managed only by the project manager","D. Defined in a contract and not changeable"],answer:1,explanation:"In Agile, scope is flexible â€” the team adapts based on customer feedback and changing needs."},
{id:1053,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"medium",question:"According to the Agile Manifesto, what BEST describes the spirit of the four values?",options:["A. The items on the left are the only things that matter","B. The items on the right have no value","C. While items on the right have value items on the left are valued more","D. Both sides of the values are equally important"],answer:2,explanation:"The manifesto explicitly states while there is value in the items on the right we value the items on the left more."},
{id:1054,chapter:"Agile Software Development",topic:"Lean",difficulty:"medium",question:"In Lean development, amplifying learning means:",options:["A. Using more experienced developers","B. Increasing feedback loops and knowledge sharing to improve the system","C. Writing more documentation","D. Conducting longer sprint planning sessions"],answer:1,explanation:"Amplifying learning means building in feedback loops and sharing knowledge to continuously improve the process."},
{id:1055,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"easy",question:"What is the purpose of a retrospective in Agile?",options:["A. To demonstrate the sprint increment","B. To reflect on the process and identify improvements","C. To plan the next iteration","D. To update the product backlog"],answer:1,explanation:"A retrospective allows the team to inspect how they worked together and identify process improvements."},
{id:1056,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"hard",question:"In Scrum, who has the final say on the ordering of the product backlog?",options:["A. Scrum Master","B. Development Team","C. Product Owner","D. Stakeholders"],answer:2,explanation:"The Product Owner has final authority over the ordering of items in the product backlog."},
{id:1057,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"medium",question:"What is the purpose of continuous integration in XP?",options:["A. To merge code once per release","B. To detect integration problems early by integrating code frequently","C. To eliminate the need for testing","D. To automate deployment to production"],answer:1,explanation:"Continuous integration catches integration problems early by integrating and testing code frequently."},
{id:1058,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"medium",question:"The Agile principle that the best architectures emerge from self-organizing teams implies:",options:["A. Architecture should never be planned upfront","B. Teams have the authority and responsibility to make technical decisions","C. Only architects can design the system","D. Architecture documentation is unnecessary"],answer:1,explanation:"Self-organizing teams are trusted to make technical decisions collaboratively, allowing architectures to emerge organically."},
{id:1059,chapter:"Agile Software Development",topic:"Kanban",difficulty:"easy",question:"What does a Kanban board primarily consist of?",options:["A. A list of bugs","B. Columns representing workflow stages and cards representing work items","C. A Gantt chart","D. A test execution log"],answer:1,explanation:"A Kanban board uses columns for workflow stages and cards for work items, providing visual flow management."},
{id:1060,chapter:"Agile Software Development",topic:"Lean",difficulty:"hard",question:"In Lean, deciding as late as possible means:",options:["A. Procrastinating on decisions","B. Making decisions when you have the most information just before action is needed","C. Never making decisions under uncertainty","D. Delegating all decisions to management"],answer:1,explanation:"Last responsible moment means waiting until you have sufficient information before committing to a decision."},
{id:1061,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"easy",question:"What does the product increment represent in Scrum?",options:["A. The complete product backlog","B. The sum of all completed product backlog items in a sprint","C. The sprint goal","D. The velocity of the team"],answer:1,explanation:"The product increment is the sum of all completed and accepted product backlog items from current and all previous sprints."},
{id:1062,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"hard",question:"In XP, on-site customer means:",options:["A. The customer must be physically present in the office","B. A representative of the customer is available to the team full time to answer questions","C. The customer owns all source code","D. Customer meetings must occur on company premises"],answer:1,explanation:"The on-site customer in XP means a real customer representative is continuously available to answer questions."},
{id:1063,chapter:"Agile Software Development",topic:"Agile vs Traditional",difficulty:"hard",question:"What is the MAIN risk of applying Agile to a fixed-price fixed-scope contract?",options:["A. The customer gets too much involvement","B. The flexibility required by Agile conflicts with the rigidity of fixed contracts","C. Sprints are too long for fixed-price work","D. Agile teams cannot estimate costs"],answer:1,explanation:"Fixed-price fixed-scope contracts conflict with Agile's need for flexibility to change scope and priorities."},
{id:1064,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"medium",question:"Which of the following BEST describes a cross-functional Agile team?",options:["A. A team where everyone has the same skills","B. A team with all skills needed to deliver a working product without external dependencies","C. A team that works across multiple departments","D. A team managed by multiple managers"],answer:1,explanation:"A cross-functional team has all the skills needed to deliver a working product increment independently."},
{id:1065,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"hard",question:"Which Agile principle directly addresses the importance of technical quality?",options:["A. Deliver working software frequently","B. Continuous attention to technical excellence and good design enhances agility","C. Simplicity is essential","D. Customer collaboration over contract negotiation"],answer:1,explanation:"Continuous attention to technical excellence maintains the team's ability to deliver quickly and respond to change."},
{id:1066,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"What is a sprint goal?",options:["A. The number of story points to complete","B. A short objective that the team commits to achieving during the sprint","C. The list of user stories in the sprint backlog","D. The velocity target for the sprint"],answer:1,explanation:"A sprint goal is a brief statement of what the team intends to achieve in the sprint, providing focus."},
{id:1067,chapter:"Agile Software Development",topic:"Lean",difficulty:"extreme",question:"A team spends 40% of their time in meetings that produce no decisions. In Lean terms this is BEST categorized as:",options:["A. Necessary waste","B. Pure waste consuming resources without adding value","C. Value-adding activity","D. Investment in team building"],answer:1,explanation:"Meetings without outcomes are pure waste in Lean â€” they consume resources without adding value to the product."},
{id:1068,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"extreme",question:"XP coding standards primarily serve to:",options:["A. Allow managers to evaluate developer performance","B. Support collective code ownership by ensuring consistent readable code throughout","C. Satisfy external audit requirements","D. Prevent developers from using new technologies"],answer:1,explanation:"Coding standards support collective code ownership by ensuring all team members can read and understand any part of the codebase."},
{id:1069,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"extreme",question:"A team lead argues the Agile Manifesto means they should stop writing all process documentation. Which response is MOST accurate?",options:["A. They are correct â€” Agile eliminates all process documentation","B. They are incorrect â€” Agile values individuals over processes but documentation still has value","C. They are correct only if using Kanban","D. Documentation decisions should be made by the customer"],answer:1,explanation:"The Manifesto values individuals over processes but explicitly states items on the right still have value."},
{id:1070,chapter:"Agile Software Development",topic:"Kanban",difficulty:"extreme",question:"A Kanban team wants to reduce lead time. Which action is MOST effective?",options:["A. Increase WIP limits to process more items","B. Identify and remove the bottleneck in the value stream","C. Hire more developers","D. Reduce the size of user stories"],answer:1,explanation:"Identifying and resolving bottlenecks is the most effective way to reduce overall lead time in a Kanban system."},
{id:1071,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"hard",question:"What is an impediment in Scrum?",options:["A. A user story that is too large","B. Anything that is blocking or slowing down the Development Team","C. A defect found during testing","D. A missing requirement"],answer:1,explanation:"An impediment is any obstacle or blocker that prevents the team from making progress."},
{id:1072,chapter:"Agile Software Development",topic:"Agile vs Traditional",difficulty:"medium",question:"In Agile the iron triangle of project constraints is typically represented as:",options:["A. Scope-Time-Cost all fixed","B. Time and Cost are fixed; Scope is variable","C. Scope is fixed; Time and Cost vary","D. All three are equally variable"],answer:1,explanation:"In Agile, time (sprints) and cost (team size) are typically fixed, while scope is variable to maximize value."},
{id:1073,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"medium",question:"What is the system metaphor in XP?",options:["A. An analogy used to explain the system to stakeholders","B. A shared story that explains how the system works guiding design and naming","C. A type of user story format","D. Documentation replacing UML diagrams"],answer:1,explanation:"The system metaphor in XP is a shared understanding that guides design decisions and naming conventions."},
{id:1074,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"easy",question:"How often should Agile teams deliver working software?",options:["A. Once at the end of the project","B. Frequently from a couple of weeks to a couple of months","C. Only when all features are complete","D. Daily"],answer:1,explanation:"Agile principles recommend delivering working software frequently â€” from weeks to a couple of months."},
{id:1075,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"hard",question:"What is the purpose of a working agreement in Agile?",options:["A. A legal contract between team members","B. A shared understanding of how the team will work together","C. A list of user stories for the sprint","D. A document signed by management"],answer:1,explanation:"A working agreement is a shared set of norms the team agrees to follow for how they will collaborate."},
{id:1076,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"In Scrum, velocity is BEST described as:",options:["A. The speed at which code is written","B. The amount of work a team completes during a sprint measured in story points","C. The number of defects fixed per sprint","D. The total cost of development per sprint"],answer:1,explanation:"Velocity measures how much work in story points a team completes per sprint, used for future sprint planning."},
{id:1077,chapter:"Agile Software Development",topic:"Lean",difficulty:"medium",question:"The Lean concept of seeing the whole means:",options:["A. Having a single manager with total visibility","B. Optimizing the entire value stream rather than individual parts","C. Testing all features before any release","D. Requiring all team members to understand all features"],answer:1,explanation:"See the whole means optimizing the entire value stream end-to-end, not just individual components."},
{id:1078,chapter:"Agile Software Development",topic:"Kanban",difficulty:"medium",question:"What is throughput in Kanban?",options:["A. The time to complete a single work item","B. The number of items completed per unit of time","C. The total number of items in the backlog","D. The WIP limit for a column"],answer:1,explanation:"Throughput is the number of items completed per unit of time â€” a key delivery rate metric in Kanban."},
{id:1079,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"easy",question:"What does simple design mean in XP?",options:["A. Using the simplest possible user interface","B. Building only what is needed now not speculative future features","C. Avoiding all design documentation","D. Using only simple programming languages"],answer:1,explanation:"Simple design in XP means building the simplest solution that works today, avoiding over-engineering."},
{id:1080,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"easy",question:"The Agile Manifesto was created by how many individuals?",options:["A. 4","B. 12","C. 17","D. 22"],answer:2,explanation:"The Agile Manifesto was created in 2001 by 17 software practitioners at the Snowbird ski resort."},
{id:1081,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"hard",question:"What is the purpose of backlog refinement?",options:["A. To remove completed items from the backlog","B. To review, estimate, and order upcoming backlog items to prepare for future sprints","C. To present the backlog to stakeholders","D. To archive old user stories"],answer:1,explanation:"Backlog refinement ensures upcoming items are well-understood, estimated, and properly ordered before sprint planning."},
{id:1082,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"medium",question:"The Agile principle of simplicity is defined as:",options:["A. Making the UI as simple as possible","B. Maximizing the amount of work NOT done","C. Using the fewest tools possible","D. Writing as little code as possible"],answer:1,explanation:"Simplicity means maximizing the amount of work not done â€” avoiding unnecessary features and complexity."},
{id:1083,chapter:"Agile Software Development",topic:"Lean",difficulty:"easy",question:"In Lean, Just In Time delivery means:",options:["A. Delivering software just before the deadline","B. Delivering what is needed when it is needed in the amount needed","C. Testing just before release","D. Writing code just when it is required by the customer"],answer:1,explanation:"JIT means delivering exactly what is needed, precisely when needed, avoiding waste from overproduction."},
{id:1084,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"medium",question:"What does whole team quality mean in Agile?",options:["A. Only QA engineers are responsible for quality","B. Everyone on the team shares responsibility for quality","C. Quality is measured by the number of tests passing","D. Quality reviews happen at the end of the project"],answer:1,explanation:"In Agile, quality is everyone's responsibility â€” developers, testers, POs, and all team members."},
{id:1085,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"What is the difference between a Sprint Backlog and a Product Backlog?",options:["A. They are the same thing","B. Product Backlog contains all desired work; Sprint Backlog contains items for the current sprint","C. Sprint Backlog is created by the Product Owner","D. Product Backlog is used in Kanban; Sprint Backlog in Scrum"],answer:1,explanation:"The Product Backlog is the master list; the Sprint Backlog is the subset selected for the current sprint."},
{id:1086,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"hard",question:"In XP, what is meant by the 40-hour work week practice?",options:["A. Developers must work exactly 40 hours per week","B. The team should not regularly work overtime â€” sustainable pace is critical","C. Overtime is permitted but must be pre-approved","D. Testing must be completed within 40 hours per sprint"],answer:1,explanation:"XP enforces sustainable pace â€” consistent overtime leads to errors and burnout."},
{id:1087,chapter:"Agile Software Development",topic:"Agile vs Traditional",difficulty:"hard",question:"Why is Agile LESS suitable for safety-critical systems?",options:["A. Agile teams cannot write good code","B. Regulatory and safety requirements demand comprehensive documentation and formal verification","C. Agile is too fast for safety-critical development","D. Agile teams cannot work with hardware"],answer:1,explanation:"Safety-critical systems require rigorous documentation and formal verification that Agile's flexible approach can struggle to satisfy."},
{id:1088,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"medium",question:"What year was the Agile Manifesto published?",options:["A. 1999","B. 2001","C. 2003","D. 2005"],answer:1,explanation:"The Agile Manifesto was published in February 2001 at the Snowbird ski resort in Utah."},
{id:1089,chapter:"Agile Software Development",topic:"Kanban",difficulty:"hard",question:"What distinguishes Kanban from Scrum primarily?",options:["A. Kanban requires daily standups; Scrum does not","B. Kanban has no time-boxed iterations; Scrum uses sprints","C. Kanban is only used for software development","D. Scrum has no WIP limits; Kanban requires them"],answer:1,explanation:"Kanban is flow-based with no time boxes, while Scrum uses fixed-length sprints as its primary structure."},
{id:1090,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"easy",question:"Which Agile principle supports constant communication between business and technical people?",options:["A. Welcome changing requirements","B. Business people and developers must work together daily throughout the project","C. Deliver working software frequently","D. Simplicity is essential"],answer:1,explanation:"Daily collaboration between business and technical people is a key Agile principle ensuring alignment and fast decisions."},
{id:1091,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"easy",question:"How long is a Sprint in Scrum?",options:["A. Exactly 2 weeks","B. Exactly 1 month","C. 1-4 weeks time-boxed","D. Variable duration based on workload"],answer:2,explanation:"Sprints are time-boxed to one month or less, with the specific duration chosen by the team."},
{id:1092,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"medium",question:"What is a user story in XP?",options:["A. A detailed requirements specification","B. A brief description of a feature told from the user perspective","C. A technical description of a module","D. A type of bug report"],answer:1,explanation:"A user story is a simple, user-centric description of a desired feature, often in As a I want so that format."},
{id:1093,chapter:"Agile Software Development",topic:"Lean",difficulty:"medium",question:"What does defer commitment mean in Lean?",options:["A. Never making architectural decisions","B. Keeping options open until the last responsible moment to have maximum information","C. Delaying delivery of features","D. Avoiding commitments to customers"],answer:1,explanation:"Deferring commitment means keeping decisions open as long as responsibly possible to have the most information."},
{id:1094,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"easy",question:"What is the purpose of a sprint review?",options:["A. Reviewing team performance","B. Demonstrating completed work to stakeholders for feedback","C. Reflecting on the process","D. Planning the next sprint"],answer:1,explanation:"The sprint review demonstrates completed work to stakeholders and collects feedback to update the product backlog."},
{id:1095,chapter:"Agile Software Development",topic:"Agile vs Traditional",difficulty:"easy",question:"In traditional waterfall development, when is testing typically performed?",options:["A. Throughout the entire project","B. During a dedicated phase after development is complete","C. Only before deployment","D. Before requirements are written"],answer:1,explanation:"In waterfall, testing is a distinct phase that occurs after development is complete, late in the lifecycle."},
{id:1096,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"hard",question:"Which of the following BEST explains why Agile values individuals and interactions over processes and tools?",options:["A. Processes and tools are always counterproductive","B. Human judgment communication and collaboration solve problems that no process or tool can substitute","C. Processes slow down delivery","D. Tools increase project costs"],answer:1,explanation:"Human interaction and collaboration address unique problems that rigid processes and tools cannot replicate."},
{id:1097,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"Who creates the sprint backlog?",options:["A. The Product Owner","B. The Scrum Master","C. The Development Team during Sprint Planning","D. All stakeholders together"],answer:2,explanation:"The Development Team creates the sprint backlog during Sprint Planning by selecting items from the product backlog."},
{id:1098,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"hard",question:"What is meant by incremental design in XP?",options:["A. Adding features one at a time","B. Evolving the design continuously based on emerging understanding rather than all upfront design","C. Drawing design diagrams incrementally","D. Designing only the database schema first"],answer:1,explanation:"Incremental design means continuously evolving and refactoring the design as understanding grows."},
{id:1099,chapter:"Agile Software Development",topic:"Lean",difficulty:"hard",question:"What is muda in Lean?",options:["A. A Japanese term for quality","B. A Japanese term for waste â€” activities consuming resources without creating value","C. A Japanese term for continuous improvement","D. A Japanese term for the production flow"],answer:1,explanation:"Muda is waste â€” any activity that consumes resources without creating value for the customer."},
{id:1100,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"medium",question:"Which Agile principle states that teams should be self-organizing?",options:["A. Deliver working software frequently","B. The best architectures requirements and designs emerge from self-organizing teams","C. Simplicity is essential","D. Continuous attention to technical excellence enhances agility"],answer:1,explanation:"Self-organizing teams have the autonomy to decide how best to accomplish their work."},
{id:1101,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"What is the typical duration of a Daily Scrum?",options:["A. 30 minutes","B. 60 minutes","C. 15 minutes","D. 5 minutes"],answer:2,explanation:"The Daily Scrum is time-boxed to 15 minutes to keep it focused and efficient."},
{id:1102,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"medium",question:"What is the purpose of a planning game in XP?",options:["A. A competitive exercise between developers","B. A collaborative meeting between customers and developers to plan upcoming iterations","C. A simulation of the deployment process","D. An estimation technique using playing cards"],answer:1,explanation:"The planning game in XP is a collaborative planning activity between customers and developers to plan iterations."},
{id:1103,chapter:"Agile Software Development",topic:"Kanban",difficulty:"hard",question:"What is the difference between lead time and cycle time in Kanban?",options:["A. They are the same metric","B. Lead time includes the waiting time before work starts; cycle time starts when work begins","C. Cycle time includes all waiting; lead time starts when work begins","D. Lead time is for bugs; cycle time is for features"],answer:1,explanation:"Lead time starts from when an item is requested; cycle time starts from when work actually begins on it."},
{id:1104,chapter:"Agile Software Development",topic:"Lean",difficulty:"medium",question:"In Lean, kaizen refers to:",options:["A. A type of waste","B. Continuous improvement â€” making small incremental improvements continuously","C. A planning technique","D. A quality gate"],answer:1,explanation:"Kaizen is the Lean principle of continuous improvement through small, incremental changes over time."},
{id:1105,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"hard",question:"What is the primary purpose of an Agile information radiator?",options:["A. To generate heat in the office","B. To make project status and progress visible to the whole team and stakeholders","C. To store test results","D. To automate reporting"],answer:1,explanation:"Information radiators (like Kanban boards, burn-down charts) make status visible at a glance to everyone."},
{id:1106,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"hard",question:"What happens if the sprint goal becomes obsolete mid-sprint?",options:["A. The sprint must continue regardless","B. The Product Owner and Development Team can cancel the sprint","C. The Scrum Master extends the sprint","D. The team works on a different product"],answer:1,explanation:"A sprint can be cancelled if the sprint goal becomes obsolete â€” this is rare and decided by the Product Owner."},
{id:1107,chapter:"Agile Software Development",topic:"Agile vs Traditional",difficulty:"medium",question:"Which of the following is a characteristic of Agile teams?",options:["A. Large teams with specialized roles","B. Small cross-functional self-organizing teams","C. Teams managed by a project manager who assigns all tasks","D. Teams that work in isolation from customers"],answer:1,explanation:"Agile teams are typically small, cross-functional, and self-organizing â€” empowered to decide how to work."},
{id:1108,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"easy",question:"In XP, what does YAGNI stand for?",options:["A. You Are Generally Not Informed","B. You Ain't Gonna Need It","C. Your Agile Guide to New Implementation","D. Yet Another General Need Inventory"],answer:1,explanation:"YAGNI means You Ain't Gonna Need It â€” don't implement features until they are actually needed."},
{id:1109,chapter:"Agile Software Development",topic:"Lean",difficulty:"easy",question:"What is the Lean principle of built-in quality?",options:["A. Hiring more QA engineers","B. Building quality into the process so defects are prevented rather than inspected out","C. Testing after every line of code","D. Conducting weekly quality audits"],answer:1,explanation:"Built-in quality means embedding quality practices in the process to prevent defects rather than finding them after the fact."},
{id:1110,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"medium",question:"Agile promotes sustainable pace to:",options:["A. Reduce code output","B. Prevent burnout and maintain consistently high quality over the long term","C. Limit working hours for cost savings","D. Slow down delivery deliberately"],answer:1,explanation:"Sustainable pace prevents burnout and maintains the team's ability to deliver high quality consistently over time."},
{id:1111,chapter:"Agile Software Development",topic:"Kanban",difficulty:"medium",question:"What does the Done column on a Kanban board represent?",options:["A. Items approved by management","B. Completed work items that have been delivered or are ready for delivery","C. Items the developer considers complete but not yet tested","D. Items awaiting customer review"],answer:1,explanation:"The Done column represents items that have met all completion criteria and are delivered or ready for delivery."},
{id:1112,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"easy",question:"What is story pointing used for in Scrum?",options:["A. Estimating the financial cost of features","B. Estimating the relative effort or complexity of user stories","C. Counting the number of bugs in a story","D. Assigning priority to stories"],answer:1,explanation:"Story points are a relative measure of effort and complexity, used to estimate and plan sprint capacity."},
{id:1113,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"hard",question:"What is the purpose of the weekly cycle in XP?",options:["A. To have weekly performance reviews","B. To plan and review work on a weekly basis allowing frequent feedback and adjustment","C. To run all tests once per week","D. To release software every week without exception"],answer:1,explanation:"The weekly cycle in XP provides regular planning and review rhythm, ensuring frequent feedback and course correction."},
{id:1114,chapter:"Agile Software Development",topic:"Lean",difficulty:"hard",question:"Which Lean principle most directly addresses reducing handoffs between teams?",options:["A. Eliminate waste","B. Build integrity in","C. Deliver as fast as possible","D. Decide as late as possible"],answer:0,explanation:"Handoffs between teams are a form of waste in Lean â€” each handoff introduces delay, misunderstanding, and quality risk."},
{id:1115,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"medium",question:"What is the purpose of a team velocity chart in Agile?",options:["A. To measure individual developer performance","B. To help the team forecast how much work they can complete in future sprints","C. To track defect rates","D. To show management how productive the team is"],answer:1,explanation:"Velocity charts help teams forecast future sprint capacity based on historical delivery rates."},
{id:1116,chapter:"Agile Software Development",topic:"Agile Manifesto",difficulty:"medium",question:"Which of the following is NOT one of the four Agile Manifesto values?",options:["A. Individuals and interactions over processes and tools","B. Continuous improvement over fixed processes","C. Working software over comprehensive documentation","D. Customer collaboration over contract negotiation"],answer:1,explanation:"Continuous improvement over fixed processes is not one of the four Agile Manifesto values."},
{id:1117,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"medium",question:"What does Sprint Planning result in?",options:["A. A final release plan","B. A sprint goal and a sprint backlog","C. A completed product increment","D. An updated product backlog"],answer:1,explanation:"Sprint Planning produces two outputs: a sprint goal and a sprint backlog of items the team commits to delivering."},
{id:1118,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"medium",question:"What is acceptance testing in XP?",options:["A. Testing performed by a third-party auditor","B. Testing performed to verify that a user story meets its acceptance criteria","C. Testing that all code compiles correctly","D. Testing that all unit tests pass"],answer:1,explanation:"Acceptance testing in XP verifies that the implemented story satisfies the acceptance criteria defined by the customer."},
{id:1119,chapter:"Agile Software Development",topic:"Lean",difficulty:"extreme",question:"A team is building comprehensive logging systems no one has requested. In Lean this is MOST classified as:",options:["A. Built-in quality","B. Overproduction waste â€” building more than needed","C. Amplifying learning","D. Value-adding work"],answer:1,explanation:"Building features no one has asked for is overproduction â€” a type of waste in Lean development."},
{id:1120,chapter:"Agile Software Development",topic:"Agile Principles",difficulty:"extreme",question:"An Agile team is pressured by management to commit to a fixed feature set for the next 6 months. This MOST conflicts with:",options:["A. The principle of delivering working software frequently","B. The principle of responding to change and welcoming changing requirements","C. The principle of sustainable pace","D. The principle of self-organizing teams"],answer:1,explanation:"Committing to a fixed feature set prevents responding to change â€” directly violating a core Agile principle."},
{id:1121,chapter:"Agile Software Development",topic:"Scrum Framework",difficulty:"extreme",question:"A Scrum team has been working together for one year and their velocity has not improved in the last 6 months. This MOST likely indicates:",options:["A. The team is working at sustainable pace","B. The team may have reached a stable capacity or may need process improvements to grow","C. The team should be replaced","D. Velocity should always increase"],answer:1,explanation:"Stable velocity indicates either sustainable capacity is reached or there are process impediments limiting growth."},
{id:1122,chapter:"Agile Software Development",topic:"Collaboration",difficulty:"extreme",question:"An Agile team's Product Owner is unavailable for days at a time. The PRIMARY impact is:",options:["A. Improved developer autonomy","B. Blocked decisions, unclear priorities, and slowed delivery","C. Better sprint planning","D. More stable requirements"],answer:1,explanation:"PO unavailability blocks decisions, creates ambiguity about priorities, and delays story acceptance."},
{id:1123,chapter:"Agile Software Development",topic:"Kanban",difficulty:"extreme",question:"A Kanban team's WIP limit for Testing is 3 but there are consistently 7 items in Testing. This indicates:",options:["A. The WIP limit is being violated and should be enforced or the bottleneck addressed","B. Testing is working efficiently","C. The WIP limit should be raised to 7","D. Testers need to work faster"],answer:0,explanation:"Consistently exceeding WIP limits reveals a bottleneck that must be addressed â€” either enforce limits or remove the constraint."},
{id:1124,chapter:"Agile Software Development",topic:"XP Practices",difficulty:"extreme",question:"A team uses pair programming but one developer consistently dominates. The MOST appropriate action is:",options:["A. End pair programming entirely","B. Coach both developers on effective pairing â€” both should drive and navigate equally","C. Assign the dominant developer to solo work","D. Introduce a rule that only junior developers can pair"],answer:1,explanation:"Effective pair programming requires both participants to take active roles â€” coaching ensures the practice works as intended."},
{id:1125,chapter:"Agile Software Development",topic:"Lean",difficulty:"extreme",question:"A team has 40% of their time spent on rework due to unclear requirements. This MOST represents which type of Lean waste?",options:["A. Overproduction","B. Defects â€” rework caused by building things incorrectly the first time","C. Waiting","D. Motion"],answer:1,explanation:"Rework due to defects is the Lean waste of defects â€” building things incorrectly that must be redone consumes resources twice."},
{id:1126,chapter:"Fundamental Aspects of Agile Testing",topic:"Whole-Team Approach",difficulty:"easy",question:"What does the whole team approach to quality mean in Agile?",options:["A. Only QA engineers are responsible for quality","B. Quality is everyone's responsibility including developers testers and the Product Owner","C. Quality reviews happen only at the end of the sprint","D. Testers approve all code before it is merged"],answer:1,explanation:"The whole team approach means every team member is responsible for quality, not just dedicated testers."},
{id:1127,chapter:"Fundamental Aspects of Agile Testing",topic:"Tester Role in Agile",difficulty:"easy",question:"Which activity is a tester MOST likely to perform in an Agile team?",options:["A. Writing production code exclusively","B. Participating in sprint planning and writing acceptance criteria","C. Managing the product backlog","D. Leading sprint retrospectives"],answer:1,explanation:"In Agile, testers actively participate in sprint planning, help define acceptance criteria, and collaborate with the whole team."},
{id:1128,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Levels in Agile",difficulty:"medium",question:"Which of the following BEST describes how testing is integrated in Agile development?",options:["A. Testing occurs only at the end of each sprint","B. Testing activities are distributed throughout the sprint alongside development","C. Testing is a separate phase after all sprints are complete","D. Testing is done only by dedicated QA teams"],answer:1,explanation:"In Agile, testing is continuous throughout the sprint â€” not a separate phase after development."},
{id:1129,chapter:"Fundamental Aspects of Agile Testing",topic:"Testing Quadrants",difficulty:"medium",question:"What are the Agile Testing Quadrants used for?",options:["A. Classifying testing types by their purpose and focus","B. Planning the number of testers per sprint","C. Organizing the product backlog","D. Measuring team velocity"],answer:0,explanation:"The Agile Testing Quadrants classify testing types by purpose â€” business-facing vs technology-facing and supporting the team vs critiquing the product."},
{id:1130,chapter:"Fundamental Aspects of Agile Testing",topic:"Testing Quadrants",difficulty:"medium",question:"Quadrant Q1 of the Agile Testing Quadrants contains tests that are:",options:["A. Business-facing and critique the product","B. Technology-facing and support the team","C. Business-facing and support the team","D. Technology-facing and critique the product"],answer:1,explanation:"Q1 contains technology-facing tests that support the team, such as unit tests and component tests."},
{id:1131,chapter:"Fundamental Aspects of Agile Testing",topic:"Testing Quadrants",difficulty:"hard",question:"Which quadrant of the Agile Testing Quadrants contains performance and security tests?",options:["A. Q1","B. Q2","C. Q3","D. Q4"],answer:3,explanation:"Q4 contains technology-facing tests that critique the product, including performance, security, and load tests."},
{id:1132,chapter:"Fundamental Aspects of Agile Testing",topic:"Tester Role in Agile",difficulty:"medium",question:"How does a tester contribute to sprint planning in Agile?",options:["A. They only observe but do not contribute","B. They help estimate testing effort and identify testability concerns","C. They define the sprint goal exclusively","D. They create the sprint backlog alone"],answer:1,explanation:"Testers contribute to sprint planning by estimating testing effort, identifying risks, and raising testability concerns."},
{id:1133,chapter:"Fundamental Aspects of Agile Testing",topic:"Regression Testing in Agile",difficulty:"medium",question:"Why is automated regression testing especially important in Agile?",options:["A. It replaces manual testing entirely","B. Frequent releases require rapid verification that existing functionality is not broken","C. It satisfies audit requirements","D. It reduces the need for test planning"],answer:1,explanation:"Agile's frequent iterations require fast regression testing â€” automation ensures existing features remain intact with each change."},
{id:1134,chapter:"Fundamental Aspects of Agile Testing",topic:"Agile Test Strategy",difficulty:"medium",question:"In Agile, a test strategy is BEST described as:",options:["A. A fixed document written at the start of the project","B. A living document adapted throughout the project","C. A detailed plan for each test case","D. A contract between the tester and Product Owner"],answer:1,explanation:"In Agile, the test strategy is a living document that evolves as the project progresses."},
{id:1135,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Independence",difficulty:"medium",question:"In an Agile team where developers write automated tests, why might an independent tester still add value?",options:["A. They provide a different perspective and may find issues developers overlook","B. They are required by regulatory authorities","C. They produce the test plan","D. They approve user stories"],answer:0,explanation:"Independent testers bring a different perspective, finding issues that developers familiar with the code may overlook."},
{id:1136,chapter:"Fundamental Aspects of Agile Testing",topic:"Whole-Team Approach",difficulty:"hard",question:"A developer writes tests but never consults the tester. Which Agile testing principle is MOST likely being violated?",options:["A. Automated testing","B. Whole-team approach to quality","C. Test automation pyramid","D. Shift-left testing"],answer:1,explanation:"The whole team approach requires collaboration between all roles â€” testers and developers must work together on quality."},
{id:1137,chapter:"Fundamental Aspects of Agile Testing",topic:"Tester Role in Agile",difficulty:"hard",question:"In Agile, what is the MAIN risk when the only tester on a team leaves mid-project?",options:["A. No one can write code","B. The whole team must take on testing responsibilities potentially reducing quality","C. The product backlog will be lost","D. Sprints will be cancelled"],answer:1,explanation:"When a dedicated tester leaves, the whole team must cover testing â€” quality may suffer if they lack testing skills."},
{id:1138,chapter:"Fundamental Aspects of Agile Testing",topic:"Testing Quadrants",difficulty:"hard",question:"Which quadrant of the Agile Testing Quadrants contains exploratory testing and user acceptance testing?",options:["A. Q1","B. Q2","C. Q3","D. Q4"],answer:2,explanation:"Q3 contains business-facing tests that critique the product, such as exploratory testing, UAT, and usability testing."},
{id:1139,chapter:"Fundamental Aspects of Agile Testing",topic:"Regression Testing in Agile",difficulty:"hard",question:"An Agile team runs full regression tests manually after every sprint. This practice is MOST likely causing:",options:["A. Better test coverage","B. Unsustainable testing effort that slows delivery","C. Improved stakeholder confidence","D. More reliable software"],answer:1,explanation:"Manual full regression after every sprint is unsustainable â€” automation is needed to maintain Agile pace."},
{id:1140,chapter:"Fundamental Aspects of Agile Testing",topic:"Agile Test Strategy",difficulty:"hard",question:"Which approach to test strategy is MOST aligned with Agile principles?",options:["A. Define complete test strategy before development starts","B. Use a risk-based adaptive strategy that evolves with the project","C. Follow a standard test strategy template from a previous project","D. Delegate all strategy decisions to the test manager"],answer:1,explanation:"An adaptive risk-based test strategy that evolves fits Agile's iterative nature better than a rigid upfront plan."},
{id:1141,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Independence",difficulty:"hard",question:"What is the MAIN advantage of having testers embedded in the Agile team versus a separate QA department?",options:["A. Testers have more management authority","B. Faster feedback loops and better collaboration on quality throughout the sprint","C. Testing can be eliminated from some sprints","D. Testers can write production code"],answer:1,explanation:"Embedded testers provide immediate feedback and collaborate closely with developers throughout the sprint."},
{id:1142,chapter:"Fundamental Aspects of Agile Testing",topic:"Whole-Team Approach",difficulty:"extreme",question:"An Agile team has no dedicated testers relying entirely on developers to test. What is the PRIMARY risk?",options:["A. Tests will be too detailed","B. Developers may lack testing skills and perspective leading to blind spots in quality","C. Test automation will not work","D. The Definition of Done cannot be met"],answer:1,explanation:"Developers testing their own code may miss defects due to familiarity bias and limited testing expertise."},
{id:1143,chapter:"Fundamental Aspects of Agile Testing",topic:"Testing Quadrants",difficulty:"extreme",question:"A team wants to use Q2 tests to support the team. Which test type BEST fits Q2?",options:["A. Unit tests","B. Functional tests including user story tests and prototypes","C. Performance tests","D. Security penetration tests"],answer:1,explanation:"Q2 contains business-facing tests that support the team, such as functional tests, story tests, and prototypes."},
{id:1144,chapter:"Fundamental Aspects of Agile Testing",topic:"Regression Testing in Agile",difficulty:"extreme",question:"An Agile team finds that regression tests take 8 hours to run per sprint. This MOST impacts:",options:["A. The product backlog size","B. The team's ability to get fast feedback and maintain sprint cadence","C. The number of user stories per sprint","D. The sprint retrospective"],answer:1,explanation:"Slow regression test suites limit feedback speed and hinder the team's ability to maintain rapid iteration cadence."},
{id:1145,chapter:"Fundamental Aspects of Agile Testing",topic:"Agile Test Strategy",difficulty:"extreme",question:"In Agile, who is responsible for defining the overall test approach for a release?",options:["A. The Test Manager working separately from the team","B. The whole team collaboratively with the tester providing testing expertise","C. The Product Owner exclusively","D. The Scrum Master"],answer:1,explanation:"In Agile, the whole team owns the test approach with testers contributing expertise."},
{id:1146,chapter:"Fundamental Aspects of Agile Testing",topic:"Tester Role in Agile",difficulty:"easy",question:"In Agile, when should a tester start testing a user story?",options:["A. After the entire sprint is complete","B. As soon as a story is developed within the same sprint","C. Only after all stories in the release are done","D. After the Product Owner approves the story"],answer:1,explanation:"In Agile, testing starts as soon as a story is developed â€” within the same sprint to provide fast feedback."},
{id:1147,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Levels in Agile",difficulty:"easy",question:"Which test level focuses on verifying individual functions or methods in isolation?",options:["A. System testing","B. Integration testing","C. Unit testing","D. Acceptance testing"],answer:2,explanation:"Unit testing verifies individual functions or methods in isolation, typically written by developers."},
{id:1148,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Levels in Agile",difficulty:"medium",question:"In Agile, system testing verifies:",options:["A. Individual classes and methods","B. The entire integrated system against requirements","C. Database schema correctness","D. Individual user stories only"],answer:1,explanation:"System testing verifies the whole integrated system against its specified requirements and user stories."},
{id:1149,chapter:"Fundamental Aspects of Agile Testing",topic:"Whole-Team Approach",difficulty:"medium",question:"A Product Owner writes acceptance criteria with the tester before development starts. This is an example of:",options:["A. Waterfall documentation","B. The three amigos practice","C. A definition of done violation","D. Gold plating"],answer:1,explanation:"Three amigos (developer, tester, PO) collaborating before development is a key Agile quality practice."},
{id:1150,chapter:"Fundamental Aspects of Agile Testing",topic:"Tester Role in Agile",difficulty:"medium",question:"Which of the following BEST describes the shift-left testing approach?",options:["A. Moving testers to a different team","B. Starting testing earlier in the development lifecycle","C. Testing on the left side of the Kanban board","D. Reducing the number of test cases"],answer:1,explanation:"Shift-left means moving testing earlier in the lifecycle to catch defects sooner when they are cheaper to fix."},
{id:1151,chapter:"Fundamental Aspects of Agile Testing",topic:"Regression Testing in Agile",difficulty:"medium",question:"What is the test automation pyramid?",options:["A. A hierarchy showing more unit tests at the base fewer UI tests at the top","B. A pyramid showing more manual tests at the base","C. A model for organizing the product backlog","D. A risk assessment framework"],answer:0,explanation:"The test automation pyramid recommends many unit tests at the base, fewer integration tests in the middle, and fewest UI tests at the top."},
{id:1152,chapter:"Fundamental Aspects of Agile Testing",topic:"Agile Test Strategy",difficulty:"medium",question:"In Agile, what does test early and test often mean?",options:["A. Tests should only be written before development","B. Testing activities should begin as early as possible and continue throughout development","C. All features must be tested every day","D. Testers should work before developers in each sprint"],answer:1,explanation:"Test early and often means starting testing from the first sprint and running tests continuously throughout development."},
{id:1153,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Independence",difficulty:"easy",question:"Why might a team use a dedicated tester separate from the developer writing the code?",options:["A. To slow down development","B. To provide an independent perspective less biased by implementation knowledge","C. Because developers cannot write tests","D. To satisfy legal requirements"],answer:1,explanation:"Independent testers are less familiar with implementation details, making them more likely to find unexpected defects."},
{id:1154,chapter:"Fundamental Aspects of Agile Testing",topic:"Testing Quadrants",difficulty:"easy",question:"Brian Marick's Testing Quadrants model was designed to help teams:",options:["A. Prioritize defect fixing","B. Plan a balanced set of testing activities across different perspectives","C. Estimate sprint velocity","D. Organize the product backlog"],answer:1,explanation:"The Testing Quadrants help teams plan a comprehensive and balanced set of testing activities."},
{id:1155,chapter:"Fundamental Aspects of Agile Testing",topic:"Whole-Team Approach",difficulty:"hard",question:"In Agile, what is the purpose of a definition of done for testing?",options:["A. To list all test cases that must be written","B. To define shared criteria the team uses to determine when a story is truly complete","C. To specify the number of tests per story","D. To assign testing tasks to team members"],answer:1,explanation:"The Definition of Done includes testing criteria â€” the team shares a common understanding of what done means."},
{id:1156,chapter:"Fundamental Aspects of Agile Testing",topic:"Tester Role in Agile",difficulty:"hard",question:"A tester notices many stories have unclear acceptance criteria. The BEST action is to:",options:["A. Test the stories without acceptance criteria","B. Raise the issue with the Product Owner and team to improve acceptance criteria before development","C. Skip testing those stories","D. Write the acceptance criteria alone after testing"],answer:1,explanation:"Testers should proactively engage with POs to clarify acceptance criteria before development starts â€” preventing defects."},
{id:1157,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Levels in Agile",difficulty:"hard",question:"Integration testing in Agile MOST typically focuses on:",options:["A. Testing the complete system against all requirements","B. Verifying that components and services work correctly together","C. Testing individual functions in isolation","D. Performing user acceptance testing"],answer:1,explanation:"Integration testing verifies that components interact correctly â€” APIs, services, and modules working together."},
{id:1158,chapter:"Fundamental Aspects of Agile Testing",topic:"Testing Quadrants",difficulty:"hard",question:"Q2 tests in the Agile Testing Quadrants are BEST described as:",options:["A. Tests that critique the product from a technical perspective","B. Business-facing tests that support the team like functional and story tests","C. Tests that find performance bottlenecks","D. Tests that check security vulnerabilities"],answer:1,explanation:"Q2 sits in the business-facing support-the-team quadrant â€” functional tests, story tests, and prototypes."},
{id:1159,chapter:"Fundamental Aspects of Agile Testing",topic:"Regression Testing in Agile",difficulty:"hard",question:"A team has 500 automated regression tests running in 3 minutes. A new sprint adds 50 tests. Which concern is MOST relevant?",options:["A. The tests are too fast","B. Test suite growth may eventually slow the feedback loop if not managed","C. 550 tests are too many","D. New tests should replace old ones"],answer:1,explanation:"Unmanaged growth of the regression suite can eventually slow feedback â€” teams must keep the suite fast and relevant."},
{id:1160,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Independence",difficulty:"extreme",question:"A team debates whether to use developers or external testers for acceptance testing. The PRIMARY advantage of external testers is:",options:["A. They are cheaper","B. They bring unbiased perspective and represent real user viewpoints","C. They have more technical skills","D. They complete testing faster"],answer:1,explanation:"External testers bring independent perspective and may better represent user viewpoints, reducing confirmation bias."},
{id:1161,chapter:"Fundamental Aspects of Agile Testing",topic:"Whole-Team Approach",difficulty:"extreme",question:"In a mature Agile team, quality is BEST maintained by:",options:["A. A dedicated QA gate at the end of each sprint","B. Built-in quality practices throughout development including TDD peer reviews and continuous testing","C. External audits after each release","D. The Scrum Master reviewing all code"],answer:1,explanation:"Mature Agile teams build quality in continuously through TDD, code reviews, automated testing, and collaboration."},
{id:1162,chapter:"Fundamental Aspects of Agile Testing",topic:"Tester Role in Agile",difficulty:"extreme",question:"An Agile tester is asked to mentor developers on writing better unit tests. This is an example of:",options:["A. Role confusion","B. The whole team quality approach â€” testers contributing testing expertise to all team members","C. Overstepping the tester responsibilities","D. Replacing the developer role"],answer:1,explanation:"Testers coaching developers on test quality is a healthy whole-team quality practice in Agile."},
{id:1163,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Levels in Agile",difficulty:"extreme",question:"An Agile team skips system testing and relies only on unit and integration tests. What is the MAIN risk?",options:["A. Unit tests will break","B. End-to-end system behavior and interactions may not be verified","C. The sprint will be cancelled","D. The Product Owner will reject the increment"],answer:1,explanation:"System testing verifies the complete system behavior â€” skipping it risks missing defects that only emerge at the system level."},
{id:1164,chapter:"Fundamental Aspects of Agile Testing",topic:"Testing Quadrants",difficulty:"extreme",question:"A team only uses Q1 tests (unit tests). Which types of testing risk are they taking?",options:["A. No risk â€” unit tests cover everything","B. Missing business validation exploratory performance and security testing from Q2 Q3 and Q4","C. Tests will run too fast","D. The backlog will grow"],answer:1,explanation:"Relying only on Q1 leaves the team without business validation, exploratory, UAT, performance, and security coverage."},
{id:1165,chapter:"Fundamental Aspects of Agile Testing",topic:"Whole-Team Approach",difficulty:"medium",question:"Which of the following BEST demonstrates the whole team approach to quality?",options:["A. Only the test team reviews the Definition of Done","B. All team members including developers and PO contribute to defining and meeting quality standards","C. Quality is reviewed by an external team at the end of each sprint","D. Developers hand off work to testers after completing all stories"],answer:1,explanation:"Whole team quality means all team members â€” developers, testers, PO â€” share ownership of quality standards."},
{id:1166,chapter:"Fundamental Aspects of Agile Testing",topic:"Tester Role in Agile",difficulty:"medium",question:"In Agile what is the tester's role during sprint planning?",options:["A. To approve all stories before they enter the sprint","B. To provide testing estimates and identify testability issues for planned stories","C. To create the sprint backlog","D. To manage the product backlog priority"],answer:1,explanation:"Testers participate in sprint planning by providing testing effort estimates and identifying any testability concerns."},
{id:1167,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Levels in Agile",difficulty:"medium",question:"What is component testing in Agile?",options:["A. Testing the complete system","B. Testing individual software components in isolation or integration","C. Testing user interfaces only","D. Testing database queries"],answer:1,explanation:"Component testing verifies individual software components or modules work correctly, often using stubs and drivers."},
{id:1168,chapter:"Fundamental Aspects of Agile Testing",topic:"Agile Test Strategy",difficulty:"easy",question:"What is a test approach in Agile?",options:["A. A detailed test plan for the entire project","B. How the team intends to test the product â€” techniques tools and levels used","C. A list of all test cases","D. The Definition of Done for testing"],answer:1,explanation:"A test approach describes how the team will test â€” the techniques, tools, levels, and focus areas they will use."},
{id:1169,chapter:"Fundamental Aspects of Agile Testing",topic:"Regression Testing in Agile",difficulty:"easy",question:"Why is regression testing important in Agile?",options:["A. To test new features only","B. To ensure changes do not break previously working functionality","C. To replace all manual testing","D. To improve team velocity"],answer:1,explanation:"Regression testing ensures that new changes don't break existing functionality â€” critical in Agile's rapid iteration environment."},
{id:1170,chapter:"Fundamental Aspects of Agile Testing",topic:"Test Independence",difficulty:"hard",question:"What is the MAIN benefit of having testers review user stories before development begins?",options:["A. To slow down the development team","B. To identify ambiguities and missing acceptance criteria early reducing defects","C. To assign work to developers","D. To replace the Product Owner"],answer:1,explanation:"Tester review of stories before development catches ambiguity early â€” preventing defects from being built in."},
{id:1171,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test-Driven Development",difficulty:"easy",question:"In TDD, what is the correct sequence of steps?",options:["A. Write code, write test, refactor","B. Write failing test, write code to pass, refactor","C. Refactor, write test, write code","D. Write test, refactor, write code"],answer:1,explanation:"TDD follows Red-Green-Refactor: write a failing test, write minimal code to pass it, then refactor."},
{id:1172,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test-Driven Development",difficulty:"easy",question:"What type of tests does TDD primarily produce?",options:["A. Performance tests","B. Unit tests","C. Acceptance tests","D. End-to-end tests"],answer:1,explanation:"TDD primarily produces unit tests â€” small, focused tests written before the code they verify."},
{id:1173,chapter:"Agile Testing Methods Techniques and Tools",topic:"ATDD",difficulty:"easy",question:"What does ATDD stand for?",options:["A. Automated Test-Driven Design","B. Acceptance Test-Driven Development","C. Advanced Test Design Discipline","D. Agile Test Delivery Directive"],answer:1,explanation:"ATDD stands for Acceptance Test-Driven Development â€” acceptance tests are written before coding begins."},
{id:1174,chapter:"Agile Testing Methods Techniques and Tools",topic:"ATDD",difficulty:"medium",question:"In ATDD, acceptance tests are typically written:",options:["A. After the feature is complete","B. Before development begins collaboratively by PO developer and tester","C. Only by the tester","D. Only by the Product Owner"],answer:1,explanation:"ATDD uses acceptance tests written collaboratively (three amigos) before development to guide implementation."},
{id:1175,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"easy",question:"What does BDD stand for?",options:["A. Bug-Driven Development","B. Behavior-Driven Development","C. Business-Driven Design","D. Baseline-Driven Delivery"],answer:1,explanation:"BDD stands for Behavior-Driven Development â€” scenarios are defined in a business-readable language like Gherkin."},
{id:1176,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"medium",question:"Which format is commonly used to write BDD scenarios?",options:["A. XML","B. Given-When-Then","C. UML sequence diagrams","D. JSON"],answer:1,explanation:"BDD scenarios use the Given-When-Then format to describe system behavior in a readable way."},
{id:1177,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"medium",question:"What is the PRIMARY benefit of BDD?",options:["A. It eliminates the need for unit tests","B. It creates a shared understanding of behavior between business and technical team members","C. It speeds up test execution","D. It replaces manual testing"],answer:1,explanation:"BDD bridges the communication gap between business and technical stakeholders by expressing behavior in plain language."},
{id:1178,chapter:"Agile Testing Methods Techniques and Tools",topic:"Exploratory Testing",difficulty:"easy",question:"What is exploratory testing?",options:["A. Testing based on a predefined test script","B. Simultaneous learning test design and test execution","C. Automated regression testing","D. Testing only new features"],answer:1,explanation:"Exploratory testing combines learning about the system, designing tests, and executing them simultaneously."},
{id:1179,chapter:"Agile Testing Methods Techniques and Tools",topic:"Exploratory Testing",difficulty:"medium",question:"Why is exploratory testing valuable in Agile?",options:["A. It replaces all scripted testing","B. It finds defects that scripted tests miss and provides rapid feedback on new features","C. It eliminates the need for automation","D. It satisfies compliance requirements"],answer:1,explanation:"Exploratory testing uncovers unexpected defects and provides fast, flexible coverage of new features."},
{id:1180,chapter:"Agile Testing Methods Techniques and Tools",topic:"User Story Testing",difficulty:"easy",question:"What are acceptance criteria in a user story?",options:["A. Technical implementation details","B. Conditions that must be met for the story to be accepted as done","C. Performance benchmarks","D. Test automation scripts"],answer:1,explanation:"Acceptance criteria define the conditions a story must satisfy to be accepted by the Product Owner."},
{id:1181,chapter:"Agile Testing Methods Techniques and Tools",topic:"User Story Testing",difficulty:"medium",question:"Which user story format is MOST commonly used in Agile?",options:["A. As a [role] I want [feature] so that [benefit]","B. When [event] happens then [outcome]","C. Given [context] when [action] then [result]","D. The system shall [do something]"],answer:0,explanation:"The standard user story format captures who wants what and why: As a role I want feature so that benefit."},
{id:1182,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test Automation in Agile",difficulty:"easy",question:"What is the MAIN advantage of test automation in Agile?",options:["A. It replaces the need for testers","B. It enables fast repeatable regression testing to support frequent releases","C. It generates requirements automatically","D. It eliminates all manual testing"],answer:1,explanation:"Automation enables fast regression testing, supporting Agile's need for rapid, frequent releases."},
{id:1183,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test Automation in Agile",difficulty:"medium",question:"Which type of test should form the LARGEST portion of the test automation pyramid?",options:["A. UI end-to-end tests","B. Unit tests","C. Integration tests","D. Performance tests"],answer:1,explanation:"The test automation pyramid recommends the largest volume of fast, reliable unit tests at the base."},
{id:1184,chapter:"Agile Testing Methods Techniques and Tools",topic:"CI/CD and Testing",difficulty:"medium",question:"What is continuous integration in the context of Agile testing?",options:["A. Testing all features once per release","B. Automatically building and testing code every time changes are committed","C. Integrating test plans with the backlog","D. Running tests in the cloud"],answer:1,explanation:"CI automatically builds and tests code on every commit, providing rapid feedback on code quality."},
{id:1185,chapter:"Agile Testing Methods Techniques and Tools",topic:"CI/CD and Testing",difficulty:"medium",question:"What is the role of automated tests in a CI/CD pipeline?",options:["A. To replace manual acceptance testing","B. To provide fast quality gates that catch defects before they reach production","C. To document test results for auditors","D. To replace all human testing"],answer:1,explanation:"Automated tests in CI/CD pipelines act as quality gates, catching defects early before they propagate downstream."},
{id:1186,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test-Driven Development",difficulty:"medium",question:"What is the red phase in TDD Red-Green-Refactor cycle?",options:["A. Writing code that has errors","B. Writing and running a failing test","C. Running all tests and finding failures","D. Deploying broken code"],answer:1,explanation:"The red phase is writing a test that currently fails â€” it defines the behavior that needs to be implemented."},
{id:1187,chapter:"Agile Testing Methods Techniques and Tools",topic:"ATDD",difficulty:"medium",question:"How does ATDD differ from TDD?",options:["A. ATDD uses acceptance criteria to drive development; TDD uses unit tests","B. ATDD is only for performance testing; TDD is for functional testing","C. ATDD is manual; TDD is automated","D. ATDD and TDD are the same practice"],answer:0,explanation:"ATDD drives development from high-level acceptance criteria, while TDD drives it from low-level unit tests."},
{id:1188,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"hard",question:"Which of the following is a BDD framework commonly used in software testing?",options:["A. JUnit","B. Cucumber","C. Selenium","D. Jenkins"],answer:1,explanation:"Cucumber is a popular BDD framework that uses Gherkin Given-When-Then syntax for feature files."},
{id:1189,chapter:"Agile Testing Methods Techniques and Tools",topic:"Exploratory Testing",difficulty:"hard",question:"What is a time-boxed exploratory testing session called?",options:["A. Sprint","B. Test charter","C. Session-based test management","D. Spike"],answer:2,explanation:"Session-based test management organizes exploratory testing into time-boxed sessions with defined charters and debrief."},
{id:1190,chapter:"Agile Testing Methods Techniques and Tools",topic:"User Story Testing",difficulty:"hard",question:"Which of the following BEST describes INVEST criteria for user stories?",options:["A. Independent Negotiable Valuable Estimable Small Testable","B. Integrated Notable Validated Expandable Scalable Tested","C. Important Novel Verified Essential Structured Timed","D. Individual New Vetted Extended Safe Tracked"],answer:0,explanation:"INVEST: Independent, Negotiable, Valuable, Estimable, Small, Testable â€” criteria for well-formed user stories."},
{id:1191,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test Automation in Agile",difficulty:"hard",question:"A team finds their UI automation tests are flaky and slow. Which solution BEST aligns with the test automation pyramid?",options:["A. Add more UI tests to improve coverage","B. Replace flaky UI tests with lower-level unit and API tests where possible","C. Remove all automation and use only manual testing","D. Run UI tests less frequently"],answer:1,explanation:"The pyramid recommends fewer targeted UI tests â€” moving coverage to unit and API tests improves speed and reliability."},
{id:1192,chapter:"Agile Testing Methods Techniques and Tools",topic:"CI/CD and Testing",difficulty:"hard",question:"What is a deployment pipeline?",options:["A. A Kanban column for deployment tasks","B. An automated process that moves code from commit through testing stages to production","C. A document describing the release process","D. A tool for managing the product backlog"],answer:1,explanation:"A deployment pipeline automates the steps from code commit through build, test, and staging to production deployment."},
{id:1193,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test-Driven Development",difficulty:"hard",question:"What is a key benefit of TDD beyond test coverage?",options:["A. Faster code writing speed","B. Improved design â€” TDD forces modular testable code by design","C. Elimination of code reviews","D. Reduced documentation needs"],answer:1,explanation:"TDD improves code design by requiring developers to write testable, loosely coupled code from the start."},
{id:1194,chapter:"Agile Testing Methods Techniques and Tools",topic:"ATDD",difficulty:"hard",question:"In ATDD, what happens when an acceptance test fails after implementation?",options:["A. The story is cancelled","B. The team debugs and fixes the implementation until the acceptance test passes","C. The acceptance criterion is removed","D. A new sprint is started"],answer:1,explanation:"A failing acceptance test indicates the implementation doesn't yet meet the agreed behavior â€” the team fixes it."},
{id:1195,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"hard",question:"In BDD, the Given-When-Then format serves to:",options:["A. Document database schemas","B. Define preconditions actions and expected outcomes in a readable scenario","C. Describe system architecture","D. Create sprint backlog items"],answer:1,explanation:"Given-When-Then describes context, action, and expected outcome clearly for both business and technical stakeholders."},
{id:1196,chapter:"Agile Testing Methods Techniques and Tools",topic:"Exploratory Testing",difficulty:"hard",question:"What is a test charter in exploratory testing?",options:["A. The formal test plan document","B. A brief mission statement that guides an exploratory test session","C. A list of all test cases to execute","D. A performance benchmark"],answer:1,explanation:"A test charter defines the scope and mission of an exploratory session: what to explore, with which approach."},
{id:1197,chapter:"Agile Testing Methods Techniques and Tools",topic:"User Story Testing",difficulty:"hard",question:"When a user story has poor acceptance criteria, what is the MOST likely consequence?",options:["A. Faster development","B. Mismatched expectations between developer and stakeholder leading to rework","C. Better test coverage","D. Reduced defect count"],answer:1,explanation:"Vague acceptance criteria lead to different interpretations, causing rework when the feature doesn't match expectations."},
{id:1198,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test Automation in Agile",difficulty:"extreme",question:"A team's automated test suite takes 45 minutes to run blocking CI feedback. The MOST appropriate action is to:",options:["A. Remove automation entirely","B. Optimize and parallelize tests; split into fast smoke and slower full suites","C. Only run tests at release time","D. Replace all tests with manual testing"],answer:1,explanation:"Parallelizing tests and splitting into fast/slow tiers maintains rapid feedback while keeping full coverage."},
{id:1199,chapter:"Agile Testing Methods Techniques and Tools",topic:"CI/CD and Testing",difficulty:"extreme",question:"In a fully automated CD pipeline, which practice ensures production deployments are safe?",options:["A. Manual approval at every stage","B. Progressive delivery with feature flags canary releases and automated rollback","C. Testing only in staging","D. Deploying only once per quarter"],answer:1,explanation:"Progressive delivery techniques like canary releases and feature flags with automated rollback make CD safe."},
{id:1200,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"extreme",question:"A team writes BDD scenarios that are too implementation-specific. What is the PRIMARY problem?",options:["A. Scenarios are too long","B. Scenarios are brittle and break with every code change rather than describing stable behavior","C. Business stakeholders write scenarios","D. Scenarios use Given-When-Then format"],answer:1,explanation:"Implementation-specific scenarios become brittle â€” they break when implementation changes even if behavior is correct."},
{id:1201,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test-Driven Development",difficulty:"extreme",question:"A developer writes tests only after completing features to get code coverage metrics. This is MOST problematic because:",options:["A. It increases test count unnecessarily","B. It defeats TDD purpose â€” tests no longer drive design and coverage may not reflect meaningful validation","C. Tests written after code are always wrong","D. It violates the Agile Manifesto"],answer:1,explanation:"Writing tests purely for coverage after the fact misses TDD's design benefits and may confirm wrong behavior."},
{id:1202,chapter:"Agile Testing Methods Techniques and Tools",topic:"ATDD",difficulty:"extreme",question:"A team using ATDD finds acceptance tests are rarely updated when requirements change. The MOST likely risk is:",options:["A. Tests run too fast","B. Acceptance tests become outdated and no longer represent current requirements","C. Developers stop writing code","D. The backlog grows unmanageable"],answer:1,explanation:"Outdated acceptance tests provide false confidence â€” they pass but no longer test the actual required behavior."},
{id:1203,chapter:"Agile Testing Methods Techniques and Tools",topic:"Exploratory Testing",difficulty:"extreme",question:"An Agile team performs exploratory testing only at the end of the release. What is the PRIMARY issue?",options:["A. Exploratory testing takes too long","B. Defects found late are expensive to fix and may delay the release","C. Exploratory testing cannot find real defects","D. The tester needs more information"],answer:1,explanation:"Exploratory testing should occur throughout iterations â€” late discovery means expensive last-minute fixes."},
{id:1204,chapter:"Agile Testing Methods Techniques and Tools",topic:"User Story Testing",difficulty:"extreme",question:"When is the BEST time to define acceptance criteria for a user story?",options:["A. After the story is implemented","B. Before the story enters the sprint during backlog refinement","C. During sprint review","D. After the first test run"],answer:1,explanation:"Defining acceptance criteria before the sprint starts ensures the team has a shared understanding before development begins."},
{id:1205,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test Automation in Agile",difficulty:"medium",question:"What does ROI stand for in the context of test automation investment?",options:["A. Return on Investment","B. Risk of Implementation","C. Range of Integration","D. Rate of Improvement"],answer:0,explanation:"ROI (Return on Investment) measures whether automation savings exceed the cost of building and maintaining it."},
{id:1206,chapter:"Agile Testing Methods Techniques and Tools",topic:"CI/CD and Testing",difficulty:"easy",question:"What is a smoke test in CI/CD?",options:["A. A test for fire safety systems","B. A quick sanity check that verifies basic functionality after a build","C. A comprehensive regression test","D. A performance test"],answer:1,explanation:"A smoke test is a fast, basic check confirming the build is stable enough for further testing."},
{id:1207,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test-Driven Development",difficulty:"easy",question:"TDD stands for:",options:["A. Test Documentation Design","B. Test-Driven Development","C. Technical Design Directive","D. Testing During Deployment"],answer:1,explanation:"TDD stands for Test-Driven Development â€” tests are written before the code they verify."},
{id:1208,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"easy",question:"In BDD, who can typically read and understand the scenarios?",options:["A. Only developers","B. Only testers","C. Business stakeholders developers and testers","D. Only project managers"],answer:2,explanation:"BDD scenarios are written in plain language so business stakeholders, developers, and testers can all understand them."},
{id:1209,chapter:"Agile Testing Methods Techniques and Tools",topic:"Exploratory Testing",difficulty:"medium",question:"Which of the following is NOT a benefit of exploratory testing?",options:["A. Discovering unexpected behavior","B. Providing fully reproducible scripted test coverage","C. Testing complex scenarios difficult to script","D. Providing quick feedback on new features"],answer:1,explanation:"Exploratory testing is unscripted by nature â€” reproducibility requires documentation of what was explored."},
{id:1210,chapter:"Agile Testing Methods Techniques and Tools",topic:"User Story Testing",difficulty:"medium",question:"What does the T in INVEST stand for for user stories?",options:["A. Trackable","B. Testable","C. Time-boxed","D. Transparent"],answer:1,explanation:"The T in INVEST stands for Testable â€” each user story must have verifiable acceptance criteria."},
{id:1211,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test Automation in Agile",difficulty:"medium",question:"What is a test stub in automated testing?",options:["A. A test that is not yet implemented","B. A simplified replacement for a component that returns predefined responses","C. A manually executed test","D. A test that always passes"],answer:1,explanation:"A test stub replaces a real component with a simplified version that returns controlled responses for testing."},
{id:1212,chapter:"Agile Testing Methods Techniques and Tools",topic:"CI/CD and Testing",difficulty:"medium",question:"What is the difference between continuous integration and continuous delivery?",options:["A. CI is manual; CD is automated","B. CI integrates and tests code continuously; CD also automates deployment to staging or production","C. CI is for testing; CD is for documentation","D. They are the same thing"],answer:1,explanation:"CI focuses on automatic integration and testing; CD extends this to automatically deploying releasable software."},
{id:1213,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test-Driven Development",difficulty:"medium",question:"What is meant by the refactor step in TDD?",options:["A. Rewriting the test","B. Improving the code structure without changing its behavior with tests still passing","C. Adding new features","D. Removing the test after it passes"],answer:1,explanation:"Refactoring cleans up code after tests pass â€” improving design without changing behavior, verified by green tests."},
{id:1214,chapter:"Agile Testing Methods Techniques and Tools",topic:"ATDD",difficulty:"hard",question:"What is the three amigos concept in ATDD?",options:["A. Three parallel test environments","B. A meeting between a developer tester and Product Owner to define acceptance criteria","C. Three layers of automated testing","D. Three rounds of review before a story is accepted"],answer:1,explanation:"Three amigos (developer, tester, PO) meet before development to collaboratively define and agree on acceptance criteria."},
{id:1215,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"hard",question:"What is the Gherkin language used for in BDD?",options:["A. Writing production code","B. Describing feature behavior in a structured human-readable format","C. Automating deployment scripts","D. Writing database queries"],answer:1,explanation:"Gherkin is a structured, human-readable DSL used to describe behavior in BDD feature files."},
{id:1216,chapter:"Agile Testing Methods Techniques and Tools",topic:"Exploratory Testing",difficulty:"easy",question:"Which of the following BEST describes a test session in exploratory testing?",options:["A. A day of formal scripted testing","B. A time-boxed focused investigation of the system with a specific charter","C. A meeting to review test cases","D. An automated test run"],answer:1,explanation:"An exploratory test session is time-boxed with a specific charter â€” focused investigation rather than open-ended browsing."},
{id:1217,chapter:"Agile Testing Methods Techniques and Tools",topic:"User Story Testing",difficulty:"easy",question:"The V in INVEST stands for:",options:["A. Verifiable","B. Valuable","C. Visual","D. Versioned"],answer:1,explanation:"The V in INVEST stands for Valuable â€” the story must deliver value to the user or customer."},
{id:1218,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test Automation in Agile",difficulty:"hard",question:"What is test flakiness in automated testing?",options:["A. Tests that always fail","B. Tests that produce inconsistent results without code changes","C. Tests that run very slowly","D. Tests that require manual review"],answer:1,explanation:"Flaky tests produce inconsistent pass/fail results with no code changes, undermining CI reliability."},
{id:1219,chapter:"Agile Testing Methods Techniques and Tools",topic:"CI/CD and Testing",difficulty:"hard",question:"What is a blue-green deployment?",options:["A. A deployment with blue and green user interfaces","B. A technique using two identical environments where traffic shifts to the new version while the old one is kept on standby","C. A type of performance test","D. A Kanban column configuration"],answer:1,explanation:"Blue-green deployment maintains two identical environments, allowing instant rollback by switching traffic back."},
{id:1220,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test-Driven Development",difficulty:"hard",question:"What does baby steps mean in TDD?",options:["A. Using small screens for testing","B. Writing the smallest possible test and code increments to move forward safely","C. Hiring junior developers","D. Reducing sprint length"],answer:1,explanation:"Baby steps in TDD means progressing in tiny increments â€” small test, small code, small refactor â€” reducing risk."},
{id:1221,chapter:"Agile Testing Methods Techniques and Tools",topic:"ATDD",difficulty:"medium",question:"What is the purpose of example mapping in ATDD?",options:["A. To create a map of the application's pages","B. To break down user stories into concrete examples rules and questions before development","C. To document test execution results","D. To map test cases to requirements"],answer:1,explanation:"Example mapping structures conversations about user stories into examples, rules, and questions to clarify acceptance criteria."},
{id:1222,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"medium",question:"Which of the following is a benefit of using BDD scenarios as executable specifications?",options:["A. They reduce the number of developers needed","B. They serve as both documentation and automated tests that verify the behavior","C. They eliminate the need for manual testing","D. They replace the product backlog"],answer:1,explanation:"BDD scenarios serve dual purpose â€” they document behavior in plain language AND can be automated as tests."},
{id:1223,chapter:"Agile Testing Methods Techniques and Tools",topic:"Exploratory Testing",difficulty:"medium",question:"What is the main difference between scripted and exploratory testing?",options:["A. Scripted testing is automated; exploratory is manual","B. Scripted follows predetermined steps; exploratory adapts dynamically based on findings","C. Exploratory is only for experienced testers","D. Scripted testing finds more defects"],answer:1,explanation:"Scripted testing follows a fixed path; exploratory testing dynamically adapts based on what the tester discovers."},
{id:1224,chapter:"Agile Testing Methods Techniques and Tools",topic:"User Story Testing",difficulty:"hard",question:"A user story says As a user I want to log in so that I can access my account. Which acceptance criterion is MOST appropriate?",options:["A. The login button must be blue","B. Given valid credentials when I submit login then I am redirected to my dashboard","C. The system shall use SHA-256 encryption","D. Login must take less than 5 seconds"],answer:1,explanation:"Acceptance criteria should describe observable behavior â€” a Given-When-Then scenario is ideal for testability."},
{id:1225,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test Automation in Agile",difficulty:"medium",question:"What is a mock object in automated testing?",options:["A. A fake product demonstration","B. A test double that verifies interactions and returns configured responses","C. A physical model of the system","D. A failing test"],answer:1,explanation:"A mock object verifies that specific interactions occurred and returns configured responses, enabling isolated unit testing."},
{id:1226,chapter:"Agile Testing Methods Techniques and Tools",topic:"CI/CD and Testing",difficulty:"medium",question:"What is shift-left testing in the context of CI/CD?",options:["A. Moving the Kanban board to the left","B. Introducing testing activities earlier in the pipeline to catch defects sooner","C. Running tests only on the left environment","D. Reducing the number of test stages"],answer:1,explanation:"Shift-left in CI/CD means introducing testing as early as possible in the pipeline â€” even at code commit time."},
{id:1227,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test-Driven Development",difficulty:"medium",question:"What is a test double in TDD?",options:["A. Running each test twice","B. An object that stands in for a real dependency during testing","C. A test that has two assertions","D. A pair of tests for positive and negative scenarios"],answer:1,explanation:"A test double is a generic term for any object used in place of a real dependency, including stubs, mocks, and fakes."},
{id:1228,chapter:"Agile Testing Methods Techniques and Tools",topic:"ATDD",difficulty:"easy",question:"In ATDD, when are acceptance tests written?",options:["A. After the sprint is complete","B. Before development begins to define expected behavior","C. During the sprint review","D. Only when bugs are found"],answer:1,explanation:"ATDD acceptance tests are written before development begins to define what done looks like."},
{id:1229,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"easy",question:"In BDD, the Given step describes:",options:["A. The action to perform","B. The initial context or precondition","C. The expected outcome","D. The test configuration"],answer:1,explanation:"The Given step sets up the initial context or precondition for the scenario."},
{id:1230,chapter:"Agile Testing Methods Techniques and Tools",topic:"Exploratory Testing",difficulty:"hard",question:"What is the debrief in session-based exploratory testing?",options:["A. A penalty for testers who find no bugs","B. A structured review after the session to share findings and assess coverage","C. The start of a new test session","D. A management report"],answer:1,explanation:"The debrief is a structured conversation after an exploratory session to share findings and assess coverage achieved."},
{id:1231,chapter:"Agile Testing Methods Techniques and Tools",topic:"User Story Testing",difficulty:"medium",question:"What does the E in INVEST stand for for user stories?",options:["A. Executable","B. Estimable","C. Expandable","D. Essential"],answer:1,explanation:"The E in INVEST stands for Estimable â€” the team must be able to estimate the effort required for the story."},
{id:1232,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test Automation in Agile",difficulty:"easy",question:"What is regression testing automation MOST used for?",options:["A. Testing new features that have never been tested before","B. Quickly re-verifying that existing functionality still works after changes","C. Creating new test strategies","D. Replacing exploratory testing"],answer:1,explanation:"Regression automation quickly re-checks existing functionality after changes, preventing regressions from shipping."},
{id:1233,chapter:"Agile Testing Methods Techniques and Tools",topic:"CI/CD and Testing",difficulty:"easy",question:"What does CD stand for in CI/CD?",options:["A. Code Deployment","B. Continuous Delivery or Continuous Deployment","C. Complete Documentation","D. Certified Developer"],answer:1,explanation:"CD stands for Continuous Delivery or Continuous Deployment â€” automating the release pipeline."},
{id:1234,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test-Driven Development",difficulty:"hard",question:"Which of the following BEST describes the green phase in TDD?",options:["A. Writing the refactored code","B. Writing the minimum code necessary to make the failing test pass","C. Running all tests and confirming they pass","D. Adding more features beyond what the test requires"],answer:1,explanation:"The green phase is writing just enough code to make the failing test pass â€” no more, no less."},
{id:1235,chapter:"Agile Testing Methods Techniques and Tools",topic:"ATDD",difficulty:"hard",question:"What is the relationship between ATDD and BDD?",options:["A. They are completely different practices with no relationship","B. BDD is a specialization of ATDD where behavior is described in natural language scenarios","C. ATDD replaces BDD in Agile projects","D. BDD is only used in non-Agile projects"],answer:1,explanation:"BDD is a variant of ATDD that uses natural language (Gherkin) scenarios to express acceptance criteria."},
{id:1236,chapter:"Agile Testing Methods Techniques and Tools",topic:"BDD",difficulty:"hard",question:"What is Living Documentation in BDD?",options:["A. Documentation that is constantly rewritten","B. BDD scenarios that are always up-to-date because they are executable tests tied to the code","C. A type of Agile meeting","D. An automated deployment tool"],answer:1,explanation:"Living documentation means BDD scenarios always reflect the current behavior because they are executable tests."},
{id:1237,chapter:"Agile Testing Methods Techniques and Tools",topic:"Exploratory Testing",difficulty:"extreme",question:"A tester finishes an exploratory session and found no bugs. What is the MOST appropriate action?",options:["A. Report that the application is bug-free","B. Document what was explored and covered then plan a session targeting different risk areas","C. Cancel future exploratory sessions","D. Report failure to management"],answer:1,explanation:"No bugs found means the explored area has low risk â€” document coverage and target unexplored risk areas next."},
{id:1238,chapter:"Agile Testing Methods Techniques and Tools",topic:"User Story Testing",difficulty:"extreme",question:"A user story has passed all acceptance tests but users still report usability issues. This MOST illustrates:",options:["A. The acceptance tests were wrong","B. Acceptance tests cover specified behavior but may miss non-functional usability qualities","C. The developers wrote bad code","D. The Definition of Done is too strict"],answer:1,explanation:"Acceptance tests verify functional behavior â€” usability and UX issues require separate exploratory and usability testing."},
{id:1239,chapter:"Agile Testing Methods Techniques and Tools",topic:"Test Automation in Agile",difficulty:"extreme",question:"A team's test automation coverage is 95% but they still frequently discover production bugs. The MOST likely cause is:",options:["A. 95% coverage is too high","B. High code coverage does not guarantee the right behaviors are being tested","C. The CI pipeline is too fast","D. Developers are writing too many tests"],answer:1,explanation:"Coverage metrics measure which lines are executed, not whether the right behaviors are asserted â€” tests can pass and still miss defects."},
{id:1240,chapter:"Agile Testing Methods Techniques and Tools",topic:"CI/CD and Testing",difficulty:"extreme",question:"A team enables continuous deployment to production but skips exploratory and UAT testing. The PRIMARY risk is:",options:["A. Deployment will be too slow","B. Automated tests may not catch all behavioral and usability defects that reach real users","C. The CI pipeline will fail","D. Story points will be wasted"],answer:1,explanation:"Automated tests in pipelines cannot replace human exploratory and acceptance testing â€” real user scenarios may be missed."},
{id:1241,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"easy",question:"In Agile, how should test progress be communicated?",options:["A. Through a formal monthly status report","B. Continuously and transparently using visible metrics and information radiators","C. Only when testing is complete","D. Through written emails to management"],answer:1,explanation:"Agile values continuous, transparent communication of test progress through visible artifacts like Kanban boards and burn-down charts."},
{id:1242,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"easy",question:"What does a burn-down chart show in Agile?",options:["A. The number of developers on the team","B. The amount of work remaining over time in a sprint","C. The number of test cases written","D. The defect density over the project"],answer:1,explanation:"A burn-down chart shows how much work remains versus time, helping the team track sprint progress."},
{id:1243,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"easy",question:"What is velocity in Agile?",options:["A. The speed of the CI pipeline","B. The average amount of work (story points) completed per sprint","C. The number of bugs fixed per sprint","D. The time to deploy a release"],answer:1,explanation:"Velocity is the average story points completed per sprint, used to forecast future capacity."},
{id:1244,chapter:"Communicating Test Status in Agile",topic:"Definition of Done",difficulty:"easy",question:"What is the Definition of Done in Agile?",options:["A. A list of features to implement","B. A shared checklist of criteria that must be met before a story is considered complete","C. The acceptance criteria for individual stories","D. The release plan"],answer:1,explanation:"The Definition of Done is a shared checklist ensuring the whole team agrees on what complete means."},
{id:1245,chapter:"Communicating Test Status in Agile",topic:"Product Backlog",difficulty:"medium",question:"What is the product backlog in Agile?",options:["A. A list of defects to fix","B. An ordered list of all desired work for the product","C. The sprint backlog for the current iteration","D. A record of completed features"],answer:1,explanation:"The product backlog is an ordered, living list of all desired features, enhancements, and fixes for the product."},
{id:1246,chapter:"Communicating Test Status in Agile",topic:"Sprint Backlog",difficulty:"medium",question:"What does the sprint backlog represent?",options:["A. All items in the product backlog","B. The set of items selected for the current sprint plus the plan for delivering them","C. The list of defects found in the current sprint","D. The product release plan"],answer:1,explanation:"The sprint backlog contains items selected from the product backlog for the current sprint plus the implementation plan."},
{id:1247,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"medium",question:"What is the purpose of a Kanban board in test status communication?",options:["A. To assign tasks to individual team members","B. To provide real-time visual status of work items through their workflow stages","C. To store test documentation","D. To generate automated reports"],answer:1,explanation:"A Kanban board gives instant visual status of all work items, enabling the whole team to see what is in progress and what is blocked."},
{id:1248,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"medium",question:"How does a tester BEST communicate a blocker during a Daily Scrum?",options:["A. Send an email after the standup","B. Briefly state the blocking issue and request help so the Scrum Master can remove the impediment","C. Wait for the sprint review to raise issues","D. Document it in the test plan"],answer:1,explanation:"Daily Scrum is the right forum to surface blockers â€” the Scrum Master can then help remove impediments."},
{id:1249,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"medium",question:"What is a test progress report in Agile?",options:["A. A formal document delivered at the end of the project","B. A lightweight regularly updated summary of test status coverage and risks","C. A list of all test cases written","D. The sprint retrospective notes"],answer:1,explanation:"Agile test progress reports are lightweight, frequently updated, and focused on status, coverage, and current risks."},
{id:1250,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"medium",question:"A burn-down chart shows the remaining work increasing mid-sprint. This MOST likely indicates:",options:["A. The team is ahead of schedule","B. New work was added or existing estimates were revised upward","C. The sprint is going perfectly","D. Velocity is improving"],answer:1,explanation:"Increasing burn-down indicates scope was added or work is more complex than estimated â€” the team should investigate."},
{id:1251,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"hard",question:"A tester needs to report on testing progress in an Agile team. The MOST appropriate way to do this is:",options:["A. Write a detailed 20-page test status report weekly","B. Update a visible information radiator daily and mention blockers at the Daily Scrum","C. Email the project manager at the end of each sprint","D. Submit a formal test completion report to the PMO"],answer:1,explanation:"Agile favors lightweight, visible, continuous communication â€” information radiators and Daily Scrum updates over formal reports."},
{id:1252,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"easy",question:"In Agile, defects found during a sprint are MOST commonly:",options:["A. Logged in a formal defect tracking system and scheduled for a future release","B. Fixed within the same sprint by the team as part of the sprint work","C. Escalated to senior management immediately","D. Added to the regression test suite without fixing"],answer:1,explanation:"Agile teams aim to fix defects within the same sprint they are found, maintaining flow and quality."},
{id:1253,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"medium",question:"Which metric helps an Agile team understand the health of their testing in a sprint?",options:["A. Number of test plans written","B. Defect density â€” defects per story point completed","C. Number of testers on the team","D. Total cost of the sprint"],answer:1,explanation:"Defect density (defects per unit of work) is a valuable quality metric showing how well the team is preventing defects."},
{id:1254,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"medium",question:"A team's velocity has dropped two sprints in a row. What should they do FIRST?",options:["A. Increase the sprint length","B. Investigate the cause in the retrospective â€” possible quality or complexity issues","C. Reduce the sprint backlog by removing testing","D. Replace team members"],answer:1,explanation:"Declining velocity is a signal to investigate root causes at the retrospective before taking action."},
{id:1255,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"hard",question:"What is the purpose of a test summary report in Agile?",options:["A. To provide a comprehensive formal document for regulatory compliance only","B. To communicate test coverage, results, risks, and open issues to stakeholders at a milestone or sprint end","C. To replace the Definition of Done","D. To substitute for the sprint retrospective"],answer:1,explanation:"A test summary report communicates coverage, results, open defects, and risks â€” useful at sprint boundaries or releases."},
{id:1256,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"easy",question:"In Kanban, which metric tells you how quickly work moves through the system?",options:["A. Velocity","B. Lead time","C. Sprint length","D. Backlog size"],answer:1,explanation:"Lead time measures how quickly work moves from request to delivery â€” a key flow efficiency metric in Kanban."},
{id:1257,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"medium",question:"What does a high cycle time indicate in an Agile team?",options:["A. The team is working very quickly","B. Work items take a long time once they are started â€” possible bottlenecks or complexity","C. The team has too few work items","D. The CI pipeline is fast"],answer:1,explanation:"High cycle time indicates items take long from start to finish, suggesting bottlenecks, complexity, or impediments."},
{id:1258,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"hard",question:"A sprint burn-down chart shows a flat line for 3 days. This MOST likely means:",options:["A. The team is making perfect progress","B. No work is being completed â€” likely a blocker or impediment exists","C. The sprint was extended","D. Velocity has doubled"],answer:1,explanation:"A flat burn-down means no work is being closed â€” the team should investigate blockers immediately."},
{id:1259,chapter:"Communicating Test Status in Agile",topic:"Definition of Done",difficulty:"medium",question:"Which of the following BEST belongs in a Definition of Done for testing?",options:["A. All code has been refactored twice","B. All acceptance tests pass, regression suite passes, no critical defects open","C. At least one new feature is added per story","D. Test plan is 100% coverage of every line of code"],answer:1,explanation:"A testing DoD typically includes passing acceptance tests, a green regression suite, and no critical open defects."},
{id:1260,chapter:"Communicating Test Status in Agile",topic:"Definition of Done",difficulty:"hard",question:"Why is a consistent Definition of Done critical for test status communication?",options:["A. It allows testers to skip testing when time is short","B. It gives stakeholders and the team a shared, objective understanding of what complete means","C. It replaces the need for acceptance criteria","D. It is only needed for regulatory compliance"],answer:1,explanation:"A shared DoD removes ambiguity about done and provides a consistent basis for communicating status."},
{id:1261,chapter:"Communicating Test Status in Agile",topic:"Sprint Backlog",difficulty:"hard",question:"A tester observes that multiple stories in the sprint backlog lack test tasks. What is the MOST appropriate action?",options:["A. Ignore them â€” developers will test on their own","B. Raise this in the Daily Scrum and collaborate with developers to add test tasks","C. Wait until sprint review to mention it","D. Close the sprint and start a new one"],answer:1,explanation:"Missing test tasks in the sprint backlog is a risk â€” testers should surface this early to ensure testing is planned."},
{id:1262,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"medium",question:"What is an information radiator in Agile?",options:["A. A physical server used for CI builds","B. A large visible display of project status and metrics accessible to the whole team","C. An automated reporting tool","D. A daily email blast with test results"],answer:1,explanation:"An information radiator is a visible display that makes project status immediately readable to anyone in the team area."},
{id:1263,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"hard",question:"In Agile, if a defect is discovered in production after a release, the BEST practice is:",options:["A. Blame the testers","B. Log it, prioritize it in the backlog, investigate root cause, and add a regression test","C. Fix it without logging it to save time","D. Ignore it unless a user reports it again"],answer:1,explanation:"Production defects should be logged, prioritized, root-caused, and covered by a new regression test to prevent recurrence."},
{id:1264,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"hard",question:"Why is velocity NOT a good metric to compare between different Agile teams?",options:["A. Velocity is only valid for Kanban","B. Teams estimate story points differently, so cross-team velocity comparisons are meaningless","C. Velocity cannot be used in scaled Agile","D. Velocity only applies to the Scrum Master"],answer:1,explanation:"Story point estimation is relative and team-specific â€” velocity measures a team's own capacity, not absolute productivity."},
{id:1265,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"medium",question:"Which type of burn-down chart shows progress across multiple sprints toward a release?",options:["A. Sprint burn-down","B. Release burn-down","C. Kanban burn-down","D. Feature burn-down"],answer:1,explanation:"A release burn-down chart tracks remaining work across all sprints toward a release goal."},
{id:1266,chapter:"Communicating Test Status in Agile",topic:"Product Backlog",difficulty:"hard",question:"How does the Product Owner communicate priority changes to the team?",options:["A. Through a formal change request document","B. By reordering the product backlog and discussing changes at backlog refinement","C. By emailing the Scrum Master only","D. By directly assigning tasks to developers"],answer:1,explanation:"The Product Owner communicates priorities through backlog ordering, communicated during refinement and planning sessions."},
{id:1267,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"extreme",question:"A stakeholder asks for a traditional status report with percentage complete. The BEST Agile response is to:",options:["A. Refuse â€” Agile does not provide status reports","B. Share the burn-down chart, velocity trend, and list of accepted stories as lightweight status information","C. Write a 10-page status report to satisfy them","D. Delay the response until the sprint review"],answer:1,explanation:"Agile teams can respond to status requests with lightweight artifacts like burn-down charts and accepted story counts."},
{id:1268,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"extreme",question:"An Agile team finds that 60% of defects come from one area of the product. The MOST beneficial action is:",options:["A. Ignore it â€” all areas will eventually have issues","B. Investigate the root cause, apply targeted testing and refactoring to that area","C. Remove that feature from the product","D. Hire additional testers for that area only"],answer:1,explanation:"Defect clustering is a test principle â€” targeted investigation and remediation of the hot spot reduces overall risk."},
{id:1269,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"extreme",question:"A Kanban team's cumulative flow diagram shows the Testing column growing wider over time. This indicates:",options:["A. Testing capacity exceeds incoming work","B. A bottleneck in testing â€” work is accumulating faster than it is being completed","C. The team is adding more testers","D. Testing quality is improving"],answer:1,explanation:"A widening band in the CFD at a stage indicates a bottleneck there â€” work is entering faster than it is leaving."},
{id:1270,chapter:"Communicating Test Status in Agile",topic:"Sprint Backlog",difficulty:"medium",question:"What is the best way to communicate blocked test work during a sprint?",options:["A. Write it in a weekly status email","B. Flag it on the sprint board as blocked and raise it in the Daily Scrum","C. Wait for the retrospective","D. Send a message to the PM after the sprint"],answer:1,explanation:"Blocked work should be immediately visible on the board and raised in the Daily Scrum so the team can resolve it quickly."},
{id:1271,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"easy",question:"Why should an Agile tester communicate test progress daily?",options:["A. To fill out timesheets","B. To keep the team informed and enable rapid response to quality issues","C. Because the PO requires written daily reports","D. To justify their role on the team"],answer:1,explanation:"Daily communication of test progress enables the team to identify quality risks early and take corrective action quickly."},
{id:1272,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"easy",question:"What is a defect triage in Agile?",options:["A. A process for deciding which defects to fix now, defer, or reject based on priority and impact","B. A formal audit of all defects in the system","C. A meeting where only testers discuss defects","D. An automated defect detection process"],answer:0,explanation:"Defect triage is the process of reviewing, prioritizing, and deciding the fate of defects â€” fix now, defer, or reject."},
{id:1273,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"easy",question:"What does a stable velocity over multiple sprints indicate?",options:["A. The team is not improving","B. The team has a predictable capacity that can be used for reliable release forecasting","C. The sprint length needs to be changed","D. The Product Owner is controlling the team"],answer:1,explanation:"Stable velocity indicates a predictable team capacity, enabling reliable forecasting of future sprint delivery."},
{id:1274,chapter:"Communicating Test Status in Agile",topic:"Definition of Done",difficulty:"easy",question:"Who on the Agile team should contribute to defining the Definition of Done?",options:["A. Only the Scrum Master","B. The whole team â€” developers, testers, PO, and Scrum Master","C. Only the QA lead","D. Only the Product Owner"],answer:1,explanation:"The Definition of Done is a whole-team agreement â€” everyone contributes to and owns the quality criteria."},
{id:1275,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"medium",question:"Which of the following is MOST appropriate to include in an Agile test progress update?",options:["A. Full test plan document","B. Stories tested and passed, stories blocked, critical open defects, and coverage gaps","C. Detailed test case scripts","D. Developer code review notes"],answer:1,explanation:"A lightweight Agile test update covers passed/blocked stories, critical defects, and coverage gaps â€” just enough information."},
{id:1276,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"medium",question:"What is throughput in Kanban?",options:["A. The time from start to finish of one item","B. The number of items completed per unit time","C. The maximum WIP limit","D. The number of defects per item"],answer:1,explanation:"Throughput is the number of items completed per unit of time, measuring the team's delivery rate."},
{id:1277,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"easy",question:"What does the ideal line on a burn-down chart represent?",options:["A. The fastest a team has ever worked","B. The expected linear rate of completion needed to finish all work by sprint end","C. The maximum number of defects allowed","D. The Product Owner's desired pace"],answer:1,explanation:"The ideal burn-down line represents the perfectly linear rate of completion needed to finish all sprint work on time."},
{id:1278,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"medium",question:"An Agile team chooses to fix only critical defects and defer minor ones. What is the risk?",options:["A. Minor defects will fix themselves over time","B. Deferred minor defects accumulate into technical debt and can become harder to fix later","C. This is always the correct approach","D. Minor defects never affect users"],answer:1,explanation:"Deferring minor defects leads to technical debt accumulation â€” what is minor today may become serious later."},
{id:1279,chapter:"Communicating Test Status in Agile",topic:"Product Backlog",difficulty:"medium",question:"In Agile, who prioritizes defect fixes relative to new features?",options:["A. The tester who found the defects","B. The Product Owner balancing business value and quality risk","C. The Scrum Master","D. The development lead"],answer:1,explanation:"The Product Owner prioritizes all backlog items â€” including defect fixes â€” based on business value and risk."},
{id:1280,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"hard",question:"What is the MOST useful indicator of testing completion at the end of a sprint?",options:["A. Number of test cases written","B. Percentage of acceptance criteria passing and zero open critical defects","C. Number of hours spent testing","D. Test documentation word count"],answer:1,explanation:"Testing completion is best measured by passing acceptance criteria and no critical open defects, not by test case count."},
{id:1281,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"hard",question:"A tester finds a critical defect on the last day of the sprint. The BEST action is:",options:["A. Hide the defect to avoid impacting sprint velocity","B. Immediately communicate the defect to the team and the Product Owner for a rapid prioritization decision","C. Fix it without testing or informing anyone","D. Wait until the next sprint planning to raise it"],answer:1,explanation:"Critical last-minute defects must be raised immediately so the team and PO can decide â€” fix, defer, or cancel sprint goal."},
{id:1282,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"medium",question:"What is story point estimation in Agile?",options:["A. Estimating the exact hours to complete a story","B. Assigning a relative size to a user story based on effort, complexity, and uncertainty","C. Counting the lines of code in a story","D. Measuring the business value of each story"],answer:1,explanation:"Story points are relative size estimates based on effort, complexity, and uncertainty â€” not precise hours."},
{id:1283,chapter:"Communicating Test Status in Agile",topic:"Sprint Backlog",difficulty:"easy",question:"What does it mean when a task on the sprint board moves to Done?",options:["A. The feature has been shipped to production","B. The task meets the Definition of Done and is considered complete","C. The developer has finished coding","D. Testing is no longer required"],answer:1,explanation:"Done on the sprint board means the item fully meets the team's Definition of Done â€” including all quality criteria."},
{id:1284,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"hard",question:"Which approach to defect tracking is MOST consistent with Agile values?",options:["A. Maintaining a complex defect database with many mandatory fields","B. Using a lightweight system focused on defect visibility, priority, and status with just enough information to act on","C. Tracking defects in email chains only","D. Tracking defects only at the end of the project"],answer:1,explanation:"Agile defect tracking should be lightweight and action-oriented â€” enough information to prioritize and act, no more."},
{id:1285,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"hard",question:"What is a service level agreement (SLA) in Kanban?",options:["A. A contract with an external vendor","B. An agreed maximum time for a specific class of work item to be completed","C. The WIP limit for the testing column","D. The daily standup duration"],answer:1,explanation:"A Kanban SLA defines the maximum acceptable lead time for a class of work, enabling predictable delivery commitments."},
{id:1286,chapter:"Communicating Test Status in Agile",topic:"Product Backlog",difficulty:"hard",question:"What is backlog refinement and how does testing benefit from it?",options:["A. Removing completed items from the backlog â€” testing benefits because there is less to test","B. Breaking down, estimating, and clarifying backlog items â€” testing benefits through early testability review","C. Writing final test plans for all backlog items at once","D. The Product Owner deciding which testers to assign to which stories"],answer:1,explanation:"Backlog refinement includes testability review, so testers can identify ambiguity and add acceptance criteria early."},
{id:1287,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"hard",question:"A burn-down chart that starts high then drops sharply at sprint end indicates:",options:["A. The team works well under pressure","B. Work was batched to sprint end rather than delivered continuously â€” a process concern","C. The team finished early","D. Velocity is excellent"],answer:1,explanation:"Work completed only at sprint end suggests a mini-waterfall pattern within the sprint â€” testing was done last and batched."},
{id:1288,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"medium",question:"In a sprint review, the tester's role in reporting is BEST described as:",options:["A. Presenting a formal test report document to stakeholders","B. Demonstrating tested, working features and reporting open quality risks to stakeholders","C. Running all automated tests live during the review","D. Staying silent while developers present"],answer:1,explanation:"In sprint review, testers contribute by demonstrating tested features and surfacing open quality concerns to stakeholders."},
{id:1289,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"medium",question:"What is a defect life cycle in Agile?",options:["A. The process a defect goes through from discovery to closure","B. The time between when a defect is introduced and when it is found","C. The list of all defects in the system","D. The defect removal efficiency metric"],answer:0,explanation:"The defect life cycle tracks a defect from discovery through triage, fix, verification, and closure."},
{id:1290,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"extreme",question:"A team reports 100% of tests passing but still has many user complaints. The MOST likely explanation is:",options:["A. Tests are passing too quickly","B. The test suite does not cover real user scenarios â€” coverage is misleading","C. Users do not understand the product","D. The CI pipeline has a bug"],answer:1,explanation:"Passing test suites with poor user experience indicate test coverage gaps â€” tests verify what was written, not all user needs."},
{id:1291,chapter:"Communicating Test Status in Agile",topic:"Sprint Backlog",difficulty:"medium",question:"What does it mean if test tasks are consistently the last items moved to Done on the sprint board?",options:["A. Testers are the slowest workers","B. Testing is being left to the end of the sprint â€” a shift-left opportunity","C. This is the ideal pattern in Agile","D. The sprint board is set up incorrectly"],answer:1,explanation:"Testing piling up at sprint end signals that testing is not shift-left â€” stories should be tested as they are developed."},
{id:1292,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"hard",question:"After adding two new team members, velocity drops for two sprints. This is MOST likely because:",options:["A. The team is less motivated","B. Onboarding new members takes time and disrupts the team's flow and capacity","C. The sprint length needs to be increased","D. The Product Owner added too many features"],answer:1,explanation:"Adding team members initially reduces velocity due to onboarding, knowledge transfer, and disruption of established flow."},
{id:1293,chapter:"Communicating Test Status in Agile",topic:"Definition of Done",difficulty:"medium",question:"What happens if a story meets the acceptance criteria but fails the Definition of Done?",options:["A. It is considered complete because acceptance criteria passed","B. It is NOT done â€” the story must meet both acceptance criteria AND the Definition of Done","C. The PO can override the DoD","D. The Scrum Master marks it done manually"],answer:1,explanation:"The Definition of Done is non-negotiable â€” a story must meet both acceptance criteria and the team's DoD to be done."},
{id:1294,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"easy",question:"What does it mean when an item has a red flag or blocker marker on a Kanban board?",options:["A. The item is urgent and should be fast-tracked","B. The item is blocked and cannot progress until an impediment is resolved","C. The item is complete","D. The item was rejected by the tester"],answer:1,explanation:"A blocker marker indicates a work item cannot progress â€” the team should immediately try to remove the impediment."},
{id:1295,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"medium",question:"How often should a sprint burn-down chart be updated?",options:["A. Once at the end of the sprint","B. Daily â€” as work is completed","C. Weekly","D. Only after testing is done"],answer:1,explanation:"Burn-down charts should be updated daily so the team has current visibility into sprint progress and remaining work."},
{id:1296,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"easy",question:"What is a test coverage matrix used for in Agile?",options:["A. To document all test case scripts","B. To map user stories or requirements to corresponding test cases ensuring all items are covered","C. To track the number of automated tests","D. To assign test cases to individual testers"],answer:1,explanation:"A coverage matrix maps requirements or stories to tests, providing visibility into what is covered and what is not."},
{id:1297,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"medium",question:"What is the BEST way to communicate a quality risk to the Product Owner?",options:["A. Wait until the retrospective to raise it","B. Communicate it immediately with a clear description of the risk, impact, and potential mitigation options","C. Write a formal risk report document","D. Discuss it only with developers"],answer:1,explanation:"Quality risks should be communicated immediately to the PO with clear impact and mitigation options so they can make informed decisions."},
{id:1298,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"easy",question:"What is defect removal efficiency (DRE)?",options:["A. The percentage of defects removed before shipping relative to total defects found","B. The speed at which developers fix defects","C. The number of defects removed per sprint","D. The automated fix rate of a CI pipeline"],answer:0,explanation:"DRE measures the percentage of total defects that were removed before release, indicating effectiveness of testing and reviews."},
{id:1299,chapter:"Communicating Test Status in Agile",topic:"Product Backlog",difficulty:"easy",question:"What is an epic in Agile?",options:["A. A large user story that is too big to complete in one sprint and must be broken down","B. A type of bug report","C. A sprint goal statement","D. A regulatory compliance requirement"],answer:0,explanation:"An epic is a large body of work that spans multiple sprints and must be broken into smaller user stories for execution."},
{id:1300,chapter:"Communicating Test Status in Agile",topic:"Sprint Backlog",difficulty:"easy",question:"In Agile, what is a task board?",options:["A. A wall display showing sprint tasks in columns like To Do, In Progress, Done","B. A spreadsheet for tracking hours","C. A formal project schedule","D. A tool for backlog prioritization"],answer:0,explanation:"A task board (sprint board) visually tracks sprint tasks through workflow stages, providing instant team status visibility."},
{id:1301,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"hard",question:"A team has 40 stories in the sprint and tests passing for 35. The sprint review is tomorrow. What should the tester communicate?",options:["A. That the sprint is complete","B. That 5 stories are untested or unresolved, communicate the risk and whether the sprint goal is still achievable","C. That testing is done","D. That all 40 stories need to be re-tested"],answer:1,explanation:"Incomplete testing creates a quality risk â€” the tester must communicate clearly what is and is not done before review."},
{id:1302,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"medium",question:"What is capacity planning in Agile?",options:["A. Setting the maximum number of users for the system","B. Estimating available team time per sprint and using it alongside velocity to plan sprint scope","C. Planning hardware infrastructure capacity","D. Setting WIP limits on the Kanban board"],answer:1,explanation:"Capacity planning estimates available person-days for the sprint to validate that planned story points are achievable."},
{id:1303,chapter:"Communicating Test Status in Agile",topic:"Definition of Done",difficulty:"hard",question:"How can a team improve their Definition of Done over time?",options:["A. By reducing the criteria to make it easier to achieve done","B. By reviewing and adding new quality criteria in retrospectives as the team matures","C. By having only the Scrum Master decide what done means","D. By keeping it fixed once defined"],answer:1,explanation:"The DoD should grow stricter over time as the team matures â€” retrospectives are the right forum for improving it."},
{id:1304,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"medium",question:"What is the WIP limit in Kanban?",options:["A. The maximum number of items allowed in a workflow stage at any time","B. The minimum number of items needed to start a sprint","C. The maximum number of stories in the backlog","D. The daily standup time limit"],answer:0,explanation:"WIP limits cap the number of items in a workflow stage, preventing overloading and improving flow."},
{id:1305,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"easy",question:"When a burn-down chart reaches zero before sprint end, what does this indicate?",options:["A. The sprint was planned with too little work","B. The team completed all sprint work early â€” either good estimation or scope was under-committed","C. The sprint was cancelled","D. Velocity dropped"],answer:1,explanation:"Reaching zero early means all planned work is done â€” the team can pull in additional backlog items or address technical debt."},
{id:1306,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"hard",question:"What is the value of a failed automated test in a CI pipeline as a communication tool?",options:["A. It has no value beyond blocking the build","B. It instantly communicates a quality issue to the whole team with context about what broke and where","C. It is only valuable to the developer who caused the failure","D. Failed tests should be suppressed to avoid alarming stakeholders"],answer:1,explanation:"A failing CI test is a real-time quality signal visible to the whole team â€” it's the fastest form of test result communication."},
{id:1307,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"medium",question:"What is the difference between a defect and a technical debt item?",options:["A. They are the same thing","B. A defect causes incorrect behavior; technical debt is a known shortcut in implementation that will need to be addressed later","C. Technical debt only affects performance","D. Defects are in the code; technical debt is in documentation"],answer:1,explanation:"Defects cause incorrect behavior; technical debt is deliberate or inadvertent design shortcuts that increase future cost."},
{id:1308,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"medium",question:"Which of the following metrics is MOST useful for tracking the QUALITY of a sprint?",options:["A. Story points planned","B. Defect escape rate â€” defects found by users after the sprint release","C. Number of sprints completed","D. CI pipeline build time"],answer:1,explanation:"Defect escape rate measures how many defects bypassed all sprint testing to reach users â€” a direct quality indicator."},
{id:1309,chapter:"Communicating Test Status in Agile",topic:"Sprint Backlog",difficulty:"hard",question:"A story is marked Done on the sprint board but the automated tests are failing. What should happen?",options:["A. Keep it Done since the developer finished the code","B. Move it back to In Progress â€” a failing test means the story does not meet the DoD","C. Ask the tester to disable the failing tests","D. Approve it anyway if the PO is happy"],answer:1,explanation:"Failing tests mean the story does not meet the DoD â€” it must move back to In Progress until all tests pass."},
{id:1310,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"extreme",question:"A team's velocity is consistently 50 points but management wants 80 points per sprint. What is the MOST appropriate response?",options:["A. Accept all 80 points and skip testing to deliver","B. Explain that velocity is a planning tool not a performance target â€” forcing more work will reduce quality","C. Reduce the point size of each story","D. Work overtime until velocity reaches 80"],answer:1,explanation:"Velocity is a planning tool, not a performance metric. Forcing velocity increases technical debt and quality problems."},
{id:1311,chapter:"Communicating Test Status in Agile",topic:"Definition of Done",difficulty:"extreme",question:"A team has a DoD requiring 80% unit test coverage. A story has 60% coverage. A manager says 'ship it'. The BEST action is:",options:["A. Ship it because the manager approved it","B. Escalate the issue transparently â€” shipping below DoD creates quality risk and should be a conscious team decision","C. Change the DoD retroactively","D. Add fake tests to meet the coverage number"],answer:1,explanation:"Bypassing the DoD is a serious quality decision. It should be explicit and visible, not hidden, so the team owns the risk."},
{id:1312,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"extreme",question:"A tester wants to show stakeholders that testing is adding value. Which metric is MOST compelling?",options:["A. Number of test cases written","B. Critical defects found before production, defect escape rate, and regression test pass rate trends","C. Hours spent testing","D. Test automation tool licensing cost"],answer:1,explanation:"Outcome-based metrics (defects caught, escape rate, regression trend) demonstrate testing value far better than activity metrics."},
{id:1313,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"extreme",question:"An Agile team never reopens defects â€” they just create new stories for unresolved issues. What is the PRIMARY risk?",options:["A. The backlog will become too large","B. Historical defect data is lost, making root cause analysis and trend detection impossible","C. The sprint board will be harder to read","D. Developers will be confused"],answer:1,explanation:"Defect history and trends enable root cause analysis and process improvement â€” losing this data impairs quality over time."},
{id:1314,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"extreme",question:"A team wants to predict when a feature will be delivered. Which Kanban metric is MOST useful?",options:["A. WIP limit","B. Historical lead time distribution â€” to forecast with a confidence interval","C. Daily standup duration","D. Number of stories in the backlog"],answer:1,explanation:"Historical lead time data enables probabilistic forecasting â€” e.g. 85% of items complete within X days."},
{id:1315,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"hard",question:"What is a risk-based testing approach in Agile?",options:["A. Testing only the most expensive features","B. Prioritizing test design and execution based on the likelihood and impact of potential failures","C. Testing features only after risk approval from management","D. Running all tests in a random order"],answer:1,explanation:"Risk-based testing focuses testing effort where the probability and impact of failure is highest."},
{id:1316,chapter:"Communicating Test Status in Agile",topic:"Sprint Backlog",difficulty:"medium",question:"In Agile, which of the following is a sign of a healthy sprint?",options:["A. All testing is done on the last day","B. Work flows steadily through the board with stories tested and accepted throughout the sprint","C. All stories are accepted only at sprint review","D. The Scrum Master approves all testing"],answer:1,explanation:"Healthy sprints show continuous, steady flow â€” stories are tested and accepted throughout, not batched at sprint end."},
{id:1317,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"easy",question:"What is the relationship between story points and hours?",options:["A. One story point always equals one hour","B. There is no fixed relationship â€” points are relative estimates, not time units","C. One story point equals one day for a senior developer","D. The Product Owner defines the hours per story point"],answer:1,explanation:"Story points are relative complexity estimates, not time units â€” the conversion to hours varies by team and context."},
{id:1318,chapter:"Communicating Test Status in Agile",topic:"Definition of Done",difficulty:"medium",question:"A team releases a product with 10 open minor defects because they are 'not critical'. This MOST violates which concept?",options:["A. Sprint planning","B. Definition of Done â€” if the DoD requires zero open defects, shipping with open defects is a DoD violation","C. Daily Scrum","D. Backlog refinement"],answer:1,explanation:"If the DoD states no open defects, shipping with open defects is a violation of the agreed quality standard."},
{id:1319,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"hard",question:"What should the team do if burn-down shows they will not complete all sprint work by sprint end?",options:["A. Extend the sprint to fit all work","B. Negotiate with the Product Owner to remove lower-priority items from the sprint backlog","C. Work overtime to force completion","D. Lower the Definition of Done criteria"],answer:1,explanation:"When sprint completion is at risk, the PO should remove lower-priority items to protect sprint goal and quality."},
{id:1320,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"medium",question:"What is the BEST use of a test execution chart in Agile?",options:["A. To replace the sprint burn-down chart","B. To show the team how many tests are passing versus failing over time and identify quality trends","C. To assign test tasks to team members","D. To document test case scripts"],answer:1,explanation:"Test execution charts show pass/fail trends over time, giving visibility into whether quality is improving or degrading."},
{id:1321,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"easy",question:"Why is transparency important in Agile testing?",options:["A. To make testers visible to management","B. Because the Agile framework requires transparency as a foundational pillar for inspection and adaptation","C. To allow stakeholders to bypass testing","D. Because legal requirements mandate it"],answer:1,explanation:"Transparency is one of the three Scrum pillars â€” without it, inspection and adaptation are impossible."},
{id:1322,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"medium",question:"What is a zero-bug policy in Agile?",options:["A. A policy requiring perfect code with no bugs ever","B. A policy where the team commits to fixing all defects before adding new features to avoid accumulating bug debt","C. A policy where testers are not allowed to report bugs","D. A policy requiring all code to have 100% test coverage"],answer:1,explanation:"A zero-bug policy prevents defect accumulation by fixing all defects immediately rather than deferring them to a backlog."},
{id:1323,chapter:"Communicating Test Status in Agile",topic:"Product Backlog",difficulty:"medium",question:"How should bug reports be handled in the Agile product backlog?",options:["A. Separately in a defect management system with no link to the backlog","B. As backlog items prioritized by the Product Owner alongside features","C. Only by the QA team with no PO involvement","D. Automatically assigned to the nearest sprint"],answer:1,explanation:"Defects are backlog items â€” the PO prioritizes them alongside features based on customer impact and business value."},
{id:1324,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"hard",question:"What does a low WIP limit on the Testing column achieve?",options:["A. It reduces the number of testers needed","B. It forces the team to complete testing on current items before starting new ones, reducing multi-tasking","C. It eliminates the need for regression testing","D. It increases the number of stories in progress"],answer:1,explanation:"Low WIP in Testing forces focus on completing current items, preventing unfinished stories from accumulating."},
{id:1325,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"medium",question:"What is a burn-up chart and how does it differ from a burn-down chart?",options:["A. They are identical","B. Burn-up shows work completed toward a target; burn-down shows remaining work â€” burn-up makes scope changes more visible","C. Burn-up is used in Kanban; burn-down only in Scrum","D. Burn-up tracks defects; burn-down tracks story points"],answer:1,explanation:"Burn-up shows completed work growing toward a target, making scope additions visible as a rise in the target line."},
{id:1326,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"easy",question:"What is regression test coverage?",options:["A. The percentage of user stories that have been tested","B. The percentage of previously tested functionality covered by the regression test suite","C. The number of automated tests in the pipeline","D. The percentage of code lines executed by any test"],answer:1,explanation:"Regression test coverage measures how much previously working functionality the regression suite verifies each run."},
{id:1327,chapter:"Communicating Test Status in Agile",topic:"Sprint Backlog",difficulty:"hard",question:"A story is repeatedly not completed within a sprint. What should the team investigate?",options:["A. Whether the tester is fast enough","B. Whether the story is too large, has unclear acceptance criteria, or has hidden dependencies","C. Whether to fire the developer","D. Whether to extend every sprint by one day"],answer:1,explanation:"Consistently incomplete stories signal poor story sizing, unclear requirements, or unresolved dependencies."},
{id:1328,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"hard",question:"A Scrum team's velocity increases by 30% after adopting TDD. What is the MOST likely explanation?",options:["A. They are writing fewer tests","B. TDD reduces rework time â€” fewer defects mean less fixing, so more capacity for new features","C. Story point inflation â€” they are estimating stories as smaller","D. The sprints have been extended"],answer:1,explanation:"TDD typically improves velocity over time by dramatically reducing defect rework, freeing capacity for new work."},
{id:1329,chapter:"Communicating Test Status in Agile",topic:"Definition of Done",difficulty:"hard",question:"What is the relationship between the Definition of Done and technical debt?",options:["A. Technical debt is tracked separately and has no relationship to the DoD","B. A weak DoD allows technical debt to accumulate; a strong DoD prevents shortcuts and maintains code quality","C. Technical debt is only created by developers, not testers","D. The DoD eliminates the possibility of any technical debt"],answer:1,explanation:"A robust DoD prevents shortcuts â€” teams that skip steps in the DoD accumulate technical debt over time."},
{id:1330,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"hard",question:"A tester wants to show quality trending over multiple sprints. What is the BEST visualization?",options:["A. A single burn-down chart","B. A multi-sprint trend chart showing defect counts, escape rates, and test pass rates per sprint","C. A list of all test cases executed","D. A pie chart of story point allocation"],answer:1,explanation:"Multi-sprint trend charts give stakeholders a longitudinal view of quality health â€” single-sprint snapshots miss trends."},
{id:1331,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"hard",question:"What is the difference between verification and validation in the context of defect fixing?",options:["A. They are the same activity","B. Verification checks the fix is correctly implemented; validation confirms it meets user needs","C. Verification is done by the tester; validation by the developer","D. Verification is automated; validation is manual only"],answer:1,explanation:"Verification confirms the fix works correctly; validation confirms it actually addresses the user's real need."},
{id:1332,chapter:"Communicating Test Status in Agile",topic:"Kanban Board Metrics",difficulty:"easy",question:"What does aging of work items in Kanban indicate?",options:["A. Items are improving with time","B. Items have been in a state for an unusually long time and may be at risk of becoming blocked","C. Items are being duplicated","D. The backlog is growing"],answer:1,explanation:"Aged items have stayed in one state too long â€” aging indicators trigger investigation to find and remove blockers."},
{id:1333,chapter:"Communicating Test Status in Agile",topic:"Product Backlog",difficulty:"hard",question:"What is DEEP in the context of product backlog management?",options:["A. Detailed, Estimated, Emergent, Prioritized","B. A framework for organizing code reviews","C. A deployment strategy","D. A method for writing user stories"],answer:0,explanation:"DEEP: Detailed appropriately, Estimated, Emergent (evolving), Prioritized â€” criteria for a healthy product backlog."},
{id:1334,chapter:"Communicating Test Status in Agile",topic:"Sprint Backlog",difficulty:"medium",question:"Why should testers be involved in sprint planning?",options:["A. To reduce the number of developers needed","B. To estimate testing effort and identify testability risks for stories before the sprint begins","C. To approve the sprint goal","D. To create the product roadmap"],answer:1,explanation:"Tester involvement in sprint planning ensures realistic estimation and surfaces testability issues before work starts."},
{id:1335,chapter:"Communicating Test Status in Agile",topic:"Burn-Down Charts",difficulty:"hard",question:"A burn-down shows steady progress until day 7 when it jumps upward sharply. What is the MOST likely explanation?",options:["A. The team doubled its speed","B. New work was added to the sprint backlog mid-sprint","C. The sprint was extended by 3 days","D. Testing found no more defects"],answer:1,explanation:"An upward jump in burn-down indicates new work was added to the sprint â€” scope was expanded after planning."},
{id:1336,chapter:"Communicating Test Status in Agile",topic:"Test Progress in Agile",difficulty:"medium",question:"What is the primary purpose of a test exit report in Agile?",options:["A. To formally close the project","B. To summarize what was tested, the results, and any residual risk as a record for the team and stakeholders","C. To replace the sprint review","D. To document all test cases for future reference"],answer:1,explanation:"A test exit report summarizes testing outcomes and residual risk, providing a record of quality at a release milestone."},
{id:1337,chapter:"Communicating Test Status in Agile",topic:"Velocity",difficulty:"medium",question:"What does it mean to say a team has a velocity of 40 story points?",options:["A. The team wrote 40 test cases in the last sprint","B. The team completed and accepted 40 story points of work in the most recent sprint","C. The team plans to do 40 points in the next sprint","D. The team has 40 open defects"],answer:1,explanation:"Velocity is the story points of completed, accepted work per sprint â€” used to forecast future sprint capacity."},
{id:1338,chapter:"Communicating Test Status in Agile",topic:"Definition of Done",difficulty:"easy",question:"At what point in the sprint should the team check against the Definition of Done?",options:["A. Only at sprint review","B. Continuously â€” each story should be checked against the DoD as it is completed","C. Once per week","D. Only at the final release"],answer:1,explanation:"The DoD should be checked continuously throughout the sprint as each story is completed, not just at the end."},
{id:1339,chapter:"Communicating Test Status in Agile",topic:"Communicating Test Results",difficulty:"medium",question:"What is the value of sharing test results with the development team immediately after test execution?",options:["A. It reduces the tester's workload","B. Immediate feedback enables developers to fix defects while the code is fresh in mind, reducing fix time","C. It satisfies regulatory requirements","D. It eliminates the need for a review meeting"],answer:1,explanation:"Immediate feedback reduces context-switching cost for developers and enables faster, more accurate defect resolution."},
{id:1340,chapter:"Communicating Test Status in Agile",topic:"Defect Management",difficulty:"hard",question:"A team discovers that 80% of defects in the last three releases came from the same two developers' code. What is the BEST approach?",options:["A. Fire those developers immediately","B. Conduct pair programming, code reviews, and targeted mentoring to improve their practices","C. Assign them less work","D. Move all defects to a separate backlog"],answer:1,explanation:"Defect patterns linked to individuals are a coaching and practice opportunity — pair programming and reviews address root causes."}
];
